{
  "name": "LabSys - Livestock Analysis Lab Management",
  "description": "A comprehensive web application to manage a quality control livestock analysis laboratory. It handles databases for clients, analyses, costs, technicians, and provides statistical insights."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import ClientManagement from './components/ClientManagement';
import TechnicianManagement from './components/TechnicianManagement';
import AnalysisManagement from './components/AnalysisManagement';
import Settings from './components/Settings';
import { View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard />;
      case 'clients':
        return <ClientManagement />;
      case 'technicians':
        return <TechnicianManagement />;
      case 'analyses':
        return <AnalysisManagement />;
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

export type View = 'dashboard' | 'clients' | 'technicians' | 'analyses' | 'settings';

export interface Client {
  id: string;
  name: string;
  contactPerson: string;
  email: string;
  phone: string;
}

export interface Technician {
  id: string;
  name: string;
  specialty: string;
  hireDate: string;
}

export interface AnalysisCost {
    id: string;
    testName: string;
    cost: number;
}

export interface Supplier {
    id: string;
    name: string;
    product: string;
}

export interface ProductType {
    id: string;
    name: string;
}

export interface Subtype {
    id: string;
    name: string;
    productTypeId: string;
}

export interface Analysis {
  id: string;
  labReference: string;
  product: string;
  subtype: string;
  clientId: string;
  technicianId: string;
  analysisDate: string;
  lot?: string;
  // Test results
  protein?: number;
  fat?: number;
  moisture?: number;
  ash?: number;
  fiber?: number;
}

import React from 'react';
import { View } from '../types';
import { DashboardIcon, ClientIcon, TechnicianIcon, AnalysisIcon, SettingsIcon } from './icons/Icons';

interface SidebarProps {
  activeView: View;
  setActiveView: (view: View) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeView, setActiveView }) => {
  const navItems: { id: View; label: string; icon: JSX.Element }[] = [
    { id: 'dashboard', label: 'Dashboard', icon: <DashboardIcon /> },
    { id: 'clients', label: 'Clients', icon: <ClientIcon /> },
    { id: 'technicians', label: 'Technicians', icon: <TechnicianIcon /> },
    { id: 'analyses', label: 'Analyses', icon: <AnalysisIcon /> },
    { id: 'settings', label: 'Settings', icon: <SettingsIcon /> },
  ];

  return (
    <aside className="w-64 bg-primary text-white flex flex-col">
      <div className="flex items-center justify-center h-20 border-b border-blue-800">
        <h1 className="text-2xl font-bold tracking-wider">LabSys</h1>
      </div>
      <nav className="flex-1 px-4 py-6">
        <ul>
          {navItems.map((item) => (
            <li key={item.id} className="mb-2">
              <a
                href="#"
                onClick={(e) => {
                  e.preventDefault();
                  setActiveView(item.id);
                }}
                className={`flex items-center p-3 rounded-lg transition-colors ${
                  activeView === item.id
                    ? 'bg-secondary'
                    : 'hover:bg-blue-800'
                }`}
              >
                {item.icon}
                <span className="ml-4 text-md font-medium">{item.label}</span>
              </a>
            </li>
          ))}
        </ul>
      </nav>
      <div className="p-4 border-t border-blue-800 text-center text-sm">
        <p>&copy; 2024 LabSys Inc.</p>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Card } from './ui/Card';

const MOCK_CLIENTS = [
    { id: 'cli1', name: 'Agropecuaria del Norte S.A.'},
    { id: 'cli2', name: 'Ganadería La Pradera'},
    { id: 'cli3', name: 'Nutrición Animal Avanzada'},
];

const MOCK_TECHNICIANS = [
    { id: 'tec1', name: 'Ana Gomez' },
    { id: 'tec2', name: 'Carlos Diaz' },
    { id: 'tec3', name: 'Sofia Luna' },
];

const MOCK_ANALYSES = [
    { id: 'an1', clientId: 'cli1', technicianId: 'tec1', cost: 150 },
    { id: 'an2', clientId: 'cli2', technicianId: 'tec2', cost: 200 },
    { id: 'an3', clientId: 'cli1', technicianId: 'tec1', cost: 120 },
    { id: 'an4', clientId: 'cli3', technicianId: 'tec3', cost: 300 },
    { id: 'an5', clientId: 'cli2', technicianId: 'tec1', cost: 180 },
    { id: 'an6', clientId: 'cli1', technicianId: 'tec2', cost: 250 },
    { id: 'an7', clientId: 'cli3', technicianId: 'tec3', cost: 220 },
];

const Dashboard: React.FC = () => {
    const totalClients = MOCK_CLIENTS.length;
    const totalAnalyses = MOCK_ANALYSES.length;
    const totalRevenue = MOCK_ANALYSES.reduce((sum, a) => sum + a.cost, 0);

    const analysesPerClient = MOCK_CLIENTS.map(client => ({
        name: client.name.split(' ')[0],
        Analyses: MOCK_ANALYSES.filter(a => a.clientId === client.id).length
    }));

    const costsPerTechnician = MOCK_TECHNICIANS.map(tech => ({
        name: tech.name,
        value: MOCK_ANALYSES
            .filter(a => a.technicianId === tech.id)
            .reduce((sum, a) => sum + a.cost, 0)
    })).filter(d => d.value > 0);

    const COLORS = ['#3b82f6', '#16a34a', '#f97316', '#dc2626'];

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Dashboard</h1>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                <Card title="Total Clients" value={totalClients.toString()} />
                <Card title="Total Analyses" value={totalAnalyses.toString()} />
                <Card title="Total Revenue" value={`$${totalRevenue.toLocaleString()}`} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white p-6 rounded-lg shadow-md">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Analyses per Client</h2>
                    <ResponsiveContainer width="100%" height={300}>
                        <BarChart data={analysesPerClient}>
                            <CartesianGrid strokeDasharray="3 3" />
                            <XAxis dataKey="name" />
                            <YAxis />
                            <Tooltip />
                            <Legend />
                            <Bar dataKey="Analyses" fill="#3b82f6" />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <div className="bg-white p-6 rounded-lg shadow-md">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Revenue per Technician</h2>
                     <ResponsiveContainer width="100%" height={300}>
                        <PieChart>
                            <Pie
                                data={costsPerTechnician}
                                cx="50%"
                                cy="50%"
                                labelLine={false}
                                outerRadius={110}
                                fill="#8884d8"
                                dataKey="value"
                                nameKey="name"
                                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                            >
                                {costsPerTechnician.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `$${value.toLocaleString()}`} />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;

import React, { useState } from 'react';
