        { id: 'cli-file-1', name: 'Imported Client 1', contactPerson: 'File Contact', email: 'file1@example.com', phone: '555-1111'},
        { id: 'cli-file-2', name: 'Imported Client 2', contactPerson: 'File Contact 2', email: 'file2@example.com', phone: '555-2222'},
      ];
      setClients(prev => [...prev, ...newClientsFromFile]);
      alert('Clients imported successfully (mocked)!');
    }
  };

  const headers = ['Name', 'Contact Person', 'Email', 'Phone'];
  const dataRows = clients.map(c => [c.name, c.contactPerson, c.email, c.phone]);

  return (
