interface AnalysisManagementProps {
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ setActiveView }) => {
    const [analyses, setAnalyses] = useState<Analysis[]>(MOCK_ANALYSES);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);

      const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
          console.log(`Uploading file: ${file.name}`);
          alert('File upload is a mock feature. Data not imported.');
        }
      };

    const handleEdit = (index: number) => {
        setEditingAnalysis(analyses[index]);
        setIsModalOpen(true);
    };

    const handleDelete = (index: number) => {
        if (window.confirm('Are you sure you want to delete this analysis?')) {
            setAnalyses(prev => prev.filter((_, i) => i !== index));
        }
    };

    const handlePrint = (index: number) => {
        handlePrintReport(analyses[index]);
    };

    const handleSave = (updatedAnalysis: Analysis) => {
        setAnalyses(prev => prev.map(a => a.id === updatedAnalysis.id ? updatedAnalysis : a));
        setIsModalOpen(false);
        setEditingAnalysis(null);
    };

    const headers = ['Folio', 'Reception', 'Delivery', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status'];
    const dataRows = analyses.map(a => [
        a.folio, 
        a.receptionDate,
        a.deliveryDate ?? 'N/A',
        a.sampleName,
        a.product,
        MOCK_CLIENTS.find(c => c.id === a.clientId)?.name ?? 'Unknown',
        MOCK_TECHNICIANS.find(t => t.id === a.technicianId)?.name ?? 'Unknown',
        a.priority,
        a.status,
    ]);

    const handleDownloadPdf = () => {
        const doc = new jsPDF();
        doc.text("Analysis Report", 14, 15);
        autoTable(doc, {
            head: [headers],
            body: dataRows,
            startY: 20,
            theme: 'grid',
            headStyles: { fillColor: [30, 64, 175] }, // primary color
        });
        doc.save('analysis-report.pdf');
    };

    const handlePrintReport = (analysis: Analysis) => {
        const doc = new jsPDF();
        const client = MOCK_CLIENTS.find(c => c.id === analysis.clientId);

        // Header
        doc.setFontSize(20);
        doc.setFont('helvetica', 'bold');
        doc.text("LabSys - Analysis Report", 105, 20, { align: 'center' });
        doc.setLineWidth(0.5);
        doc.line(20, 25, 190, 25);

        // Sample Information
        doc.setFontSize(12);
        doc.setFont('helvetica', 'bold');
        doc.text("Sample Information", 20, 35);
        doc.setFont('helvetica', 'normal');
        doc.text(`Folio: ${analysis.folio}`, 20, 42);
        doc.text(`Sample Name: ${analysis.sampleName}`, 20, 49);
        doc.text(`Product: ${analysis.product}`, 20, 56);
        doc.text(`Reception Date: ${analysis.receptionDate}`, 130, 42);
        doc.text(`Delivery Date: ${analysis.deliveryDate || 'Pending'}`, 130, 49);

        // Client Information
        doc.line(20, 65, 190, 65);
        doc.setFont('helvetica', 'bold');
        doc.text("Client Information", 20, 75);
        doc.setFont('helvetica', 'normal');
        if (client) {
            doc.text(`Client: ${client.name}`, 20, 82);
            doc.text(`Contact: ${client.contactPerson}`, 20, 89);
            doc.text(`Email: ${client.email}`, 130, 82);
            doc.text(`Phone: ${client.phone}`, 130, 89);
        } else {
            doc.text("Client not found.", 20, 82);
        }

        // Analysis Results Table
        doc.line(20, 98, 190, 98);
        const results = [];
        if (analysis.protein !== undefined && analysis.protein !== null) results.push(['Protein', `${analysis.protein.toFixed(2)} %`]);
        if (analysis.fat !== undefined && analysis.fat !== null) results.push(['Fat', `${analysis.fat.toFixed(2)} %`]);
        if (analysis.moisture !== undefined && analysis.moisture !== null) results.push(['Moisture', `${analysis.moisture.toFixed(2)} %`]);
        if (analysis.fiber !== undefined && analysis.fiber !== null) results.push(['Fiber', `${analysis.fiber.toFixed(2)} %`]);
        if (analysis.ash !== undefined && analysis.ash !== null) results.push(['Ash', `${analysis.ash.toFixed(2)} %`]);
        if (analysis.starch !== undefined && analysis.starch !== null) results.push(['Starch', `${analysis.starch.toFixed(2)} %`]);

        if (results.length > 0) {
            autoTable(doc, {
                head: [['Parameter', 'Result']],
                body: results,
                startY: 105,
                theme: 'striped',
                headStyles: { fillColor: [30, 64, 175] },
                margin: { left: 20, right: 20 },
            });
        } else {
            doc.text("No analysis results available for this sample.", 20, 110);
        }

        // Footer
        const finalY = (doc as any).lastAutoTable?.finalY || 120;
        doc.setFontSize(10);
        doc.setFont('helvetica', 'italic');
        doc.text("Report generated by LabSys. Thank you for your business.", 105, finalY + 20, { align: 'center' });
        doc.line(20, doc.internal.pageSize.height - 20, 190, doc.internal.pageSize.height - 20);
        doc.text(`Generated on: ${new Date().toLocaleDateString()}`, 20, doc.internal.pageSize.height - 15);

        doc.save(`Report-Folio-${analysis.folio}.pdf`);
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold text-gray-800">Analysis Management</h1>
                 <div className="flex items-center space-x-2">
                    <button onClick={handleDownloadPdf} className="bg-green-600 text-white hover:bg-green-700 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <DownloadIcon />
                        <span className="ml-2">Download Report</span>
                    </button>
                    <label htmlFor="analysis-upload" className="cursor-pointer bg-white text-primary hover:bg-gray-50 border border-primary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <UploadIcon />
                        <span className="ml-2">Import Analyses</span>
                    </label>
                    <input id="analysis-upload" type="file" className="hidden" accept=".csv, application/vnd.openxmlformats-officedocument.spreadsheetml.sheet, application/vnd.ms-excel" onChange={handleFileUpload} />
                    <button onClick={() => setActiveView('newAnalysis')} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <PlusIcon />
                        <span className="ml-2">Add Analysis</span>
                    </button>
                </div>
            </div>
            <Table headers={headers} data={dataRows} onEdit={handleEdit} onDelete={handleDelete} onPrint={handlePrint} />
             {isModalOpen && editingAnalysis && (
                <EditAnalysisModal 
                    analysis={editingAnalysis}
                    onClose={() => setIsModalOpen(false)}
                    onSave={handleSave}
                />
            )}
        </div>
    );
};

