                    <button onClick={handleDownloadPdf} className="bg-white text-gray-700 hover:bg-gray-100 border border-gray-300 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <DownloadIcon />
                        <span className="ml-2">Download PDF</span>
                    </button>

                    <button onClick={handleExportCSV} className="bg-green-600 text-white hover:bg-green-700 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <SheetIcon />
                        <span className="ml-2">Export CSV</span>
                    </button>

                    <button onClick={() => setActiveView('newAnalysis')} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <PlusIcon />
                        <span className="ml-2">New Analysis</span>
                    </button>
                </div>
            </div>
            <Table headers={headers} data={dataRows} onEdit={handleEdit} onDelete={handleDelete} onPrint={handlePrint} />
            {isModalOpen && editingAnalysis && (
                <Modal onClose={() => { setIsModalOpen(false); setEditingAnalysis(null); }} title={`Edit Analysis - ${editingAnalysis.folio}`}>
                    <div className="p-6">
                      <p>Editing form for the analysis would go here. For this demo, this modal is a placeholder.</p>
                      <pre className="text-xs bg-gray-100 p-4 rounded-md mt-4 overflow-auto">{JSON.stringify(editingAnalysis, null, 2)}</pre>
                    </div>
                    <div className="flex justify-end p-4 bg-gray-50 border-t">
                        <button onClick={() => { setIsModalOpen(false); setEditingAnalysis(null); }} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                            Cancel
                        </button>
                        <button onClick={() => handleSave(editingAnalysis)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                            Save Changes
                        </button>
                    </div>
                </Modal>
            )}
        </div>
    );
};

