};

export default Settings;

import React, { useState, useEffect } from 'react';
import { Analysis, Client, Technician, AnalysisPriority, AnalysisStatus, AnalysisCost } from '../types';

// MOCK DATA - In a real app, this would come from a central store or API
const MOCK_CLIENTS: Client[] = [
    { id: 'cli1', name: 'Agropecuaria del Norte S.A.', contactPerson: 'Juan Perez', email: 'jperez@adnorte.com', phone: '555-1234'},
    { id: 'cli2', name: 'Ganadería La Pradera', contactPerson: 'Maria Rodriguez', email: 'mrodriguez@pradera.com', phone: '555-5678'},
    { id: 'cli3', name: 'Nutrición Animal Avanzada', contactPerson: 'Luis Garcia', email: 'lgarcia@naa.com', phone: '555-9012'},
];
const MOCK_TECHNICIANS: Technician[] = [
    { id: 'tec1', name: 'Ana Gomez', specialty: 'Microbiology', hireDate: '2021-03-15' },
    { id: 'tec2', name: 'Carlos Diaz', specialty: 'Chemistry', hireDate: '2020-07-22' },
    { id: 'tec3', name: 'Sofia Luna', specialty: 'NIR Spectroscopy', hireDate: '2022-11-01' },
];
const MOCK_AVAILABLE_TESTS: AnalysisCost[] = [
    { id: 'c1', testName: 'Protein (Kjeldahl)', cost: 25.50 },
    { id: 'c2', testName: 'Fat (Soxhlet)', cost: 30.00 },
    { id: 'c3', testName: 'Moisture (Oven)', cost: 15.00 },
    { id: 'c4', testName: 'Fiber (Crude)', cost: 28.00 },
    { id: 'c5', testName: 'Ash (Muffle Furnace)', cost: 18.50 },
    { id: 'c6', testName: 'Starch (Polarimetry)', cost: 45.00 },
];
const MOCK_PRODUCTS: string[] = [ 'Corn', 'Soybean Meal', 'Wheat Midds', 'Fishmeal', 'DDGS' /* ... more products */ ];
const priorityOptions: AnalysisPriority[] = ['Normal', 'Urgent', 'Low'];
const statusOptions: AnalysisStatus[] = ['Received', 'In Progress', 'Completed', 'Cancelled'];

const testNameToPropertyMap: { [key: string]: keyof Analysis } = {
    'Protein (Kjeldahl)': 'protein',
    'Fat (Soxhlet)': 'fat',
    'Moisture (Oven)': 'moisture',
    'Fiber (Crude)': 'fiber',
    'Ash (Muffle Furnace)': 'ash',
    'Starch (Polarimetry)': 'starch',
};

let folioCounter = new Date().getMilliseconds(); // Simple session-based counter

const generateFolio = (): string => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const sequence = String(folioCounter++).padStart(4, '0');
    return `${year}${month}${sequence}`;
};

const initialFormData = {
    folio: '',
    receptionDate: new Date().toISOString().split('T')[0],
    deliveryDate: '',
    sampleName: '',
    product: '',
    subtype: '',
    clientId: '',
    technicianId: '',
    priority: 'Normal' as AnalysisPriority,
    status: 'Received' as AnalysisStatus,
};

interface TestResult {
    [key: string]: string;
}

const AnalysisRequest: React.FC = () => {
    const [formData, setFormData] = useState(initialFormData);
    const [selectedTests, setSelectedTests] = useState<AnalysisCost[]>([]);
    const [testResults, setTestResults] = useState<TestResult>({});
    const [totalCost, setTotalCost] = useState(0);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

    useEffect(() => {
        setFormData(prev => ({ ...prev, folio: generateFolio() }));
    }, []);

    useEffect(() => {
        const newCost = selectedTests.reduce((sum, test) => sum + test.cost, 0);
        setTotalCost(newCost);
    }, [selectedTests]);

    const handleTestSelection = (test: AnalysisCost, isChecked: boolean) => {
        if (isChecked) {
            setSelectedTests(prev => [...prev, test]);
        } else {
            setSelectedTests(prev => prev.filter(t => t.id !== test.id));
            setTestResults(prev => {
                const newResults = { ...prev };
                delete newResults[test.testName];
                return newResults;
            });
        }
    };

    const handleResultChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setTestResults(prev => ({ ...prev, [name]: value }));
    }

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setSubmitStatus('submitting');

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            alert('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        const payload: any = { ...formData, cost: totalCost };
        // Initialize all possible parameters to null
        Object.values(testNameToPropertyMap).forEach(prop => {
            payload[prop] = null;
        });
        // Populate with actual results, converting them to numbers
        for (const test of selectedTests) {
            const propertyName = testNameToPropertyMap[test.testName];
            if (propertyName) {
                const resultValue = parseFloat(testResults[test.testName]);
                payload[propertyName] = isNaN(resultValue) ? null : resultValue;
            }
        }

        try {
            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
                headers: {
                    'Content-Type': 'application/json',
                }
            });

            const result = await response.json();

            if (result.status === 'success') {
                console.log('Analysis Request Submitted to Google Sheets:', payload);
                setSubmitStatus('success');
                setTimeout(() => {
                    setFormData({ ...initialFormData, folio: generateFolio() });
                    setSelectedTests([]);
                    setTestResults({});
                    setSubmitStatus('idle');
                }, 2000);
            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }

        } catch (error) {
            console.error('Failed to submit to Google Sheets:', error);
            alert(`Failed to submit data. Error: ${error instanceof Error ? error.message : String(error)}`);
            setSubmitStatus('error');
             setTimeout(() => setSubmitStatus('idle'), 3000);
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Submitting...';
            case 'success': return 'Success!';
            case 'error': return 'Retry Submit';
            default: return 'Submit Request';
        }
    }

    return (
        <div className="space-y-8 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold text-gray-800">New Analysis Request</h1>
            <form onSubmit={handleSubmit} className="bg-white p-8 rounded-lg shadow-md space-y-6">

                {/* Sample Information */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                     <div>
                        <label htmlFor="folio" className="block text-sm font-medium text-gray-700">Folio</label>
                        <input type="text" name="folio" id="folio" value={formData.folio} required readOnly className={`${inputStyle} bg-gray-100 cursor-not-allowed`} />
                    </div>
                    <div>
                        <label htmlFor="receptionDate" className="block text-sm font-medium text-gray-700">Reception Date</label>
                        <input type="date" name="receptionDate" id="receptionDate" value={formData.receptionDate} onChange={handleChange} required className={inputStyle} />
                    </div>
                     <div>
                        <label htmlFor="sampleName" className="block text-sm font-medium text-gray-700">Sample Name</label>
                        <input type="text" name="sampleName" id="sampleName" value={formData.sampleName} onChange={handleChange} required className={inputStyle} />
                    </div>
                    <div>
                        <label htmlFor="product" className="block text-sm font-medium text-gray-700">Product</label>
                         <select name="product" id="product" value={formData.product} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a product</option>
                            {MOCK_PRODUCTS.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="clientId" className="block text-sm font-medium text-gray-700">Client</label>
                        <select name="clientId" id="clientId" value={formData.clientId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a client</option>
                            {MOCK_CLIENTS.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="technicianId" className="block text-sm font-medium text-gray-700">Assigned Technician</label>
                        <select name="technicianId" id="technicianId" value={formData.technicianId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a technician</option>
                            {MOCK_TECHNICIANS.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>
                </div>

                {/* Analysis Selection */}
                <div className="border-t pt-6">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Select Analyses</h2>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                        {MOCK_AVAILABLE_TESTS.map(test => (
                            <label key={test.id} className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg border border-gray-200 hover:bg-gray-100 cursor-pointer">
                                <input
                                    type="checkbox"
                                    onChange={(e) => handleTestSelection(test, e.target.checked)}
                                    checked={selectedTests.some(st => st.id === test.id)}
                                    className="h-5 w-5 rounded border-gray-300 text-primary focus:ring-secondary"
                                />
                                <span className="text-sm font-medium text-gray-700">{test.testName}</span>
                                <span className="text-sm text-gray-500">(${test.cost.toFixed(2)})</span>
                            </label>
                        ))}
                    </div>
                </div>

                 {/* Results & Cost */}
                {selectedTests.length > 0 && (
                     <div className="border-t pt-6">
                        <h2 className="text-xl font-semibold text-gray-700 mb-4">Analysis Results</h2>
                         <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                             {selectedTests.map(test => (
                                <div key={test.id}>
                                    <label htmlFor={test.testName} className="block text-sm font-medium text-gray-700">{test.testName.split('(')[0].trim()} (%)</label>
                                    <input 
                                        type="number" 
                                        name={test.testName} 
                                        id={test.testName} 
                                        value={testResults[test.testName] || ''}
                                        onChange={handleResultChange}
                                        className={inputStyle} 
                                        placeholder="0.00" 
                                        step="0.01"
                                    />
                                </div>
                             ))}
                         </div>
                    </div>
                )}

                {/* Cost & Submission */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 border-t pt-6">
                    <div>
                        <label htmlFor="priority" className="block text-sm font-medium text-gray-700">Priority</label>
                        <select name="priority" id="priority" value={formData.priority} onChange={handleChange} required className={inputStyle}>
                            {priorityOptions.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Total Cost ($)</label>
                        <input type="text" name="cost" id="cost" value={totalCost.toFixed(2)} readOnly className={`${inputStyle} bg-gray-100 cursor-not-allowed`} />
                    </div>
                </div>

                <div className="flex justify-end pt-6">
                    <button 
                        type="submit" 
                        className={`font-bold py-2 px-6 rounded-lg inline-flex items-center transition-colors ${
                            submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' : 
                            submitStatus === 'success' ? 'bg-green-600' : 
                            submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                            'bg-primary hover:bg-secondary'
                        } text-white`}
                        disabled={submitStatus === 'submitting' || submitStatus === 'success'}
                    >
                        {getButtonText()}
                    </button>
                </div>
            </form>
        </div>
    );
};

export default AnalysisRequest;

