interface AnalysisManagementProps {
    analyses: Analysis[];
    onUpdateAnalysis: (analysis: Analysis) => void;
    onDeleteAnalysis: (analysisId: string) => void;
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ analyses, onUpdateAnalysis, onDeleteAnalysis, setActiveView }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);
    const [modalFormData, setModalFormData] = useState<Partial<Analysis>>({});
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

      const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
          console.log(`Uploading file: ${file.name}`);
          alert('File upload is a mock feature. Data not imported.');
        }
      };

    const handleEdit = (index: number) => {
        const analysisToEdit = analyses[index];
        setEditingAnalysis(analysisToEdit);
        setModalFormData(analysisToEdit);
        setIsModalOpen(true);
    };

    const handleDelete = (index: number) => {
        if (window.confirm('Are you sure you want to delete this analysis?')) {
            const analysisToDelete = analyses[index];
            onDeleteAnalysis(analysisToDelete.id);
        }
    };

    const handlePrint = (index: number) => {
        handlePrintReport(analyses[index]);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingAnalysis(null);
        setSubmitStatus('idle');
    };

    const handleModalFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setModalFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleModalResultChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        const numericValue = value === '' ? undefined : parseFloat(value);
        setModalFormData(prev => ({...prev, [name]: numericValue }));
    }

    const handleSaveAndSubmit = async () => {
        if (!editingAnalysis) return;
        setSubmitStatus('submitting');

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            alert('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        const clientName = MOCK_CLIENTS.find(c => c.id === modalFormData.clientId)?.name || modalFormData.clientId;
        const technicianName = MOCK_TECHNICIANS.find(t => t.id === modalFormData.technicianId)?.name || modalFormData.technicianId;

        const payload: any = { ...modalFormData };
        payload.clientId = clientName;
        payload.technicianId = technicianName;

        // Ensure all possible test properties exist for the sheet
        Object.values(testNameToPropertyMap).forEach(prop => {
            if (!payload.hasOwnProperty(prop)) {
                payload[prop] = null;
            }
        });

        try {
            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
            });
            const result = await response.json();

            if (result.status === 'success') {
                onUpdateAnalysis(modalFormData as Analysis);
                setSubmitStatus('success');
                setTimeout(() => {
                    handleCloseModal();
                }, 1500);
            } else {
                 throw new Error(result.message || 'Unknown error from Google Script.');
            }
        } catch (error) {
             console.error('Failed to submit to Google Sheets:', error);
             alert(`Failed to submit data. Error: ${error instanceof Error ? error.message : String(error)}`);
             setSubmitStatus('error');
        }
    }

    const headers = ['Folio', 'Reception', 'Delivery', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status'];
    const dataRows = analyses.map(a => [
        a.folio, 
        a.receptionDate,
        a.deliveryDate ?? 'N/A',
        a.sampleName,
        a.product,
        MOCK_CLIENTS.find(c => c.id === a.clientId)?.name ?? 'Unknown',
        MOCK_TECHNICIANS.find(t => t.id === a.technicianId)?.name ?? 'Unknown',
        a.priority,
        a.status,
    ]);

    const handleDownloadPdf = () => {
        const doc = new jsPDF();
        doc.text("Analysis Report", 14, 15);
        autoTable(doc, {
            head: [headers],
            body: dataRows,
            startY: 20,
            theme: 'grid',
            headStyles: { fillColor: [30, 64, 175] }, // primary color
        });
        doc.save('analysis-report.pdf');
    };

    const handleExportCSV = () => {
        const csvHeaders = ['Folio', 'Reception Date', 'Delivery Date', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status', 'Cost ($)', 'Protein (%)', 'Fat (%)', 'Moisture (%)', 'Fiber (%)', 'Ash (%)', 'Starch (%)'];

        const escapeCsvCell = (cell: string | number | undefined | null): string => {
            const strCell = String(cell ?? '');
            if (strCell.includes(',') || strCell.includes('"') || strCell.includes('\n')) {
                return `"${strCell.replace(/"/g, '""')}"`;
            }
            return strCell;
        };

        const csvRows = analyses.map(a => {
            const clientName = MOCK_CLIENTS.find(c => c.id === a.clientId)?.name ?? 'Unknown';
            const technicianName = MOCK_TECHNICIANS.find(t => t.id === a.technicianId)?.name ?? 'Unknown';
            return [
                a.folio, a.receptionDate, a.deliveryDate, a.sampleName, a.product,
                clientName, technicianName, a.priority, a.status, a.cost,
                a.protein, a.fat, a.moisture, a.fiber, a.ash, a.starch
            ].map(escapeCsvCell).join(',');
        });

        const csvContent = [csvHeaders.join(','), ...csvRows].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", "analysis-report.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handlePrintReport = (analysis: Analysis) => {
        const doc = new jsPDF();
        const client = MOCK_CLIENTS.find(c => c.id === analysis.clientId);

        // Header
        doc.setFontSize(20);
        doc.text("Analysis Report", 105, 15, { align: 'center' });
        doc.setFontSize(12);
        doc.text(`Folio: ${analysis.folio}`, 14, 30);
        doc.text(`Client: ${client?.name ?? 'Unknown'}`, 14, 37);
        doc.text(`Sample: ${analysis.sampleName}`, 14, 44);
        doc.text(`Reception Date: ${analysis.receptionDate}`, 150, 30);
        doc.text(`Delivery Date: ${analysis.deliveryDate ?? 'N/A'}`, 150, 37);

        // Results Table
        autoTable(doc, {
            startY: 55,
            head: [['Parameter', 'Result']],
            body: Object.entries(testNameToPropertyMap).map(([testName, propName]) => {
                const result = analysis[propName];
                return [testName.split('(')[0].trim(), typeof result === 'number' ? result.toFixed(2) : 'N/A'];
            }).filter(row => analysis.requestedTests.includes(Object.keys(testNameToPropertyMap).find(key => testNameToPropertyMap[key] === testNameToPropertyMap[row[0] as keyof typeof testNameToPropertyMap])!)),
            theme: 'grid',
        });

        // Footer
        const technician = MOCK_TECHNICIANS.find(t => t.id === analysis.technicianId);
        doc.text(`Technician: ${technician?.name ?? 'Unknown'}`, 14, (doc as any).lastAutoTable.finalY + 20);

        doc.save(`report-${analysis.folio}.pdf`);
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";


    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold text-gray-800">Analysis Management</h1>
                <div className="flex items-center space-x-2">
                    <button onClick={handleDownloadPdf} className="bg-white text-gray-700 hover:bg-gray-100 border border-gray-300 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <DownloadIcon /> <span className="ml-2">Download PDF</span>
                    </button>
                    <button onClick={handleExportCSV} className="bg-green-600 text-white hover:bg-green-700 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <SheetIcon /> <span className="ml-2">Export CSV</span>
                    </button>
                    <button onClick={() => setActiveView('newAnalysis')} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <PlusIcon /> <span className="ml-2">New Analysis</span>
                    </button>
                </div>
            </div>
            <Table headers={headers} data={dataRows} onEdit={handleEdit} onDelete={handleDelete} onPrint={handlePrint} />
            {isModalOpen && editingAnalysis && (
                <Modal onClose={handleCloseModal} title={`Edit Analysis - ${editingAnalysis.folio}`}>
                    <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
                      {/* General Info */}
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label htmlFor="deliveryDate" className="block text-sm font-medium text-gray-700">Delivery Date</label>
                            <input type="date" name="deliveryDate" id="deliveryDate" value={modalFormData.deliveryDate?.split('T')[0] || ''} onChange={handleModalFormChange} className={inputStyle} />
                        </div>
                        <div>
                            <label htmlFor="status" className="block text-sm font-medium text-gray-700">Status</label>
                            <select name="status" id="status" value={modalFormData.status} onChange={handleModalFormChange} className={inputStyle}>
                                {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                      </div>

                      {/* Results Entry */}
                      <div className="border-t pt-4">
                        <h3 className="text-lg font-medium text-gray-800 mb-2">Analysis Results</h3>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                            {editingAnalysis.requestedTests.map(testName => {
                                const propName = testNameToPropertyMap[testName];
                                if (!propName) return null;
                                return (
                                    <div key={propName}>
                                        <label htmlFor={propName} className="block text-sm font-medium text-gray-700">{testName.split('(')[0].trim()} (%)</label>
                                        <input 
                                            type="number" 
                                            id={propName}
                                            name={propName}
                                            value={modalFormData[propName] ?? ''}
                                            onChange={handleModalResultChange}
                                            className={inputStyle}
                                            placeholder="0.00"
                                            step="0.01"
                                        />
                                    </div>
                                )
                            })}
                        </div>
                      </div>
                    </div>
                    <div className="flex justify-end p-4 bg-gray-50 border-t">
                        <button onClick={handleCloseModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                            Cancel
                        </button>
                        <button onClick={handleSaveAndSubmit} disabled={submitStatus === 'submitting' || submitStatus === 'success'} className={`font-bold py-2 px-4 rounded-lg transition-colors text-white ${
                             submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' : 
                             submitStatus === 'success' ? 'bg-green-600' : 
                             submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                             'bg-primary hover:bg-secondary'
                        }`}>
                            {submitStatus === 'submitting' ? 'Saving...' : submitStatus === 'success' ? 'Saved!' : 'Save & Submit to Sheet'}
                        </button>
                    </div>
                </Modal>
            )}
        </div>
    );
};

