  const [analysisCosts, setAnalysisCosts] = useState<AnalysisCost[]>(INITIAL_ANALYSIS_COSTS);

  const addAnalysis = (newAnalysis: Analysis) => {
    setAnalyses(prev => [newAnalysis, ...prev]);
  };

  const updateAnalysis = (updatedAnalysis: Analysis) => {
    setAnalyses(prev => prev.map(a => a.id === updatedAnalysis.id ? updatedAnalysis : a));
  };

  const deleteAnalysis = (analysisId: string) => {
      setAnalyses(prev => prev.filter(a => a.id !== analysisId));
  };

  const addAnalysisCost = (newCost: AnalysisCost) => {
    setAnalysisCosts(prev => [...prev, newCost]);
  };

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard />;
      case 'clients':
        return <ClientManagement />;
      case 'technicians':
        return <TechnicianManagement />;
      case 'newAnalysis':
        return <AnalysisRequest onAddAnalysis={addAnalysis} setActiveView={setActiveView} analysisCosts={analysisCosts} />;
      case 'analyses':
        return <AnalysisManagement analyses={analyses} onUpdateAnalysis={updateAnalysis} onDeleteAnalysis={deleteAnalysis} setActiveView={setActiveView} />;
      case 'settings':
        return <Settings analysisCosts={analysisCosts} onAddAnalysisCost={addAnalysisCost} />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8">
        {renderView()}
      </main>
    </div>
  );
};

