                     </p>
                    <div>
                        <label htmlFor="googleScriptUrl" className="block text-sm font-medium text-gray-700">Apps Script URL</label>
                        <input 
                            type="url" 
                            name="googleScriptUrl" 
                            id="googleScriptUrl" 
                            value={googleScriptUrl}
                            onChange={(e) => setGoogleScriptUrl(e.target.value)}
                            className={inputStyle}
                            placeholder="https://script.google.com/macros/s/..."
                        />
                    </div>
                    <div className="flex items-center space-x-2 mt-4">
                        <button onClick={handleSaveUrl} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                           Save URL
                        </button>
                        <button onClick={handleTestConnection} className="bg-gray-600 text-white hover:bg-gray-700 font-bold py-2 px-4 rounded-lg transition-colors" disabled={testStatus === 'testing'}>
                           {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
                        </button>
                        {testStatus === 'success' && <span className="text-green-600 font-medium">Connection successful!</span>}
                        {testStatus === 'error' && <span className="text-red-600 font-medium">Connection failed. Check URL and script permissions.</span>}
                    </div>
                </div>

                {/* Analysis Costs */}
                <div>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-2xl font-semibold text-gray-700">Analysis Costs</h2>
                        <button onClick={() => setIsCostModalOpen(true)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                            <PlusIcon /> <span className="ml-2">Add Cost</span>
                        </button>
                    </div>
                    <Table headers={['Test Name', 'Method', 'Cost ($)']} data={analysisCosts.map(c => [c.testName, c.method, c.cost.toFixed(2)])} />
                </div>

