import React, 'useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import ClientManagement from './components/ClientManagement';
import TechnicianManagement from './components/TechnicianManagement';
import AnalysisManagement from './components/AnalysisManagement';
import AnalysisRequest from './components/AnalysisRequest';
import Settings from './components/Settings';
import Loader from './components/ui/Loader';
import { Analysis, View, AnalysisCost, Client, Technician } from './types';

// Initial analyses can be kept for demonstration or loaded from another source/localStorage
const INITIAL_ANALYSES: Analysis[] = [
    { id: 'an1', folio: '2024070001', sampleName: 'Corn Sample A', product: 'Maíz', subtype: 'Feed Grade', clientId: 'cli1', technicianId: 'tec1', receptionDate: '2024-07-20', deliveryDate: '2024-07-25', priority: 'Normal', status: 'Completed', cost: 150, requestedTests: ['Protein (Kjeldahl)', 'Fat (Soxhlet)', 'Moisture (Oven)', 'Fiber (Crude)', 'Ash (Muffle Furnace)', 'Starch (Polarimetry)'], protein: 8.5, fat: 3.2, moisture: 12.1, fiber: 2.5, ash: 1.5, starch: 72.0 },
    { id: 'an2', folio: '2024070002', sampleName: 'Soybean Batch 3', product: 'Pasta de Soya', subtype: 'High Protein', clientId: 'cli2', technicianId: 'tec2', receptionDate: '2024-07-21', deliveryDate: '2024-07-24', priority: 'Urgent', status: 'In Progress', cost: 200, requestedTests: ['Protein (Kjeldahl)', 'Fat (Soxhlet)', 'Moisture (Oven)'], protein: 46.1, fat: 1.5, moisture: 11.5 },
];


const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [analyses, setAnalyses] = useState<Analysis[]>(INITIAL_ANALYSES);
  const [clients, setClients] = useState<Client[]>([]);
  const [technicians, setTechnicians] = useState<Technician[]>([]);
  const [analysisCosts, setAnalysisCosts] = useState<AnalysisCost[]>([]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError(null);
      const googleScriptUrl = localStorage.getItem('googleScriptUrl');

      if (!googleScriptUrl) {
        setError("Google Sheets URL not configured. Please set it in Settings.");
        setLoading(false);
        return;
      }

      try {
        const response = await fetch(googleScriptUrl);
        if (!response.ok) {
          throw new Error(`Failed to fetch data: ${response.statusText}`);
        }
        const data = await response.json();

        if (data.clients && data.technicians && data.analysisCosts) {
            setClients(data.clients);
            setTechnicians(data.technicians);
            setAnalysisCosts(data.analysisCosts);
        } else {
            throw new Error("Data from Google Sheets is not in the expected format.");
        }

      } catch (err) {
        setError(err instanceof Error ? err.message : "An unknown error occurred.");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);


  const addAnalysis = (newAnalysis: Analysis) => {
    setAnalyses(prev => [newAnalysis, ...prev]);
  };
  const updateAnalysis = (updatedAnalysis: Analysis) => {
    setAnalyses(prev => prev.map(a => a.id === updatedAnalysis.id ? updatedAnalysis : a));
  };
  const deleteAnalysis = (analysisId: string) => {
      setAnalyses(prev => prev.filter(a => a.id !== analysisId));
  };

  const addClient = (newClient: Client) => {
    setClients(prev => [...prev, newClient]);
  };
  const addTechnician = (newTechnician: Technician) => {
    setTechnicians(prev => [...prev, newTechnician]);
  }
  const addAnalysisCost = (newCost: AnalysisCost) => {
    setAnalysisCosts(prev => [...prev, newCost]);
  };

  const renderView = () => {
    if (loading) {
      return <Loader message="Loading data from Google Sheets..." />;
    }
    if (error && activeView !== 'settings') {
       return (
            <div className="text-center p-8">
                <h2 className="text-2xl font-bold text-red-600 mb-4">Data Loading Error</h2>
                <p className="text-gray-700 mb-4">{error}</p>
                <button 
                    onClick={() => setActiveView('settings')} 
                    className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors"
                >
                    Go to Settings
                </button>
            </div>
       );
    }

    switch (activeView) {
      case 'dashboard':
        return <Dashboard analyses={analyses} clients={clients} technicians={technicians} />;
      case 'clients':
        return <ClientManagement clients={clients} onAddClient={addClient} />;
      case 'technicians':
        return <TechnicianManagement technicians={technicians} onAddTechnician={addTechnician} />;
      case 'newAnalysis':
        return <AnalysisRequest onAddAnalysis={addAnalysis} setActiveView={setActiveView} analysisCosts={analysisCosts} clients={clients} technicians={technicians} />;
      case 'analyses':
        return <AnalysisManagement analyses={analyses} onUpdateAnalysis={updateAnalysis} onDeleteAnalysis={deleteAnalysis} setActiveView={setActiveView} clients={clients} technicians={technicians} />;
      case 'settings':
        return <Settings analysisCosts={analysisCosts} onAddAnalysisCost={addAnalysisCost} />;
      default:
        return <Dashboard analyses={analyses} clients={clients} technicians={technicians}/>;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Card } from './ui/Card';
import { Analysis, Client, Technician } from '../types';

interface DashboardProps {
    analyses: Analysis[];
    clients: Client[];
    technicians: Technician[];
}

const Dashboard: React.FC<DashboardProps> = ({ analyses, clients, technicians }) => {
    const totalClients = clients.length;
    const totalAnalyses = analyses.length;
    const totalRevenue = analyses.reduce((sum, a) => sum + a.cost, 0);

    const analysesPerClient = clients.map(client => ({
        name: client.name.split(' ')[0],
        Analyses: analyses.filter(a => a.clientId === client.id).length
    })).filter(c => c.Analyses > 0);

    const costsPerTechnician = technicians.map(tech => ({
        name: tech.name,
        value: analyses
            .filter(a => a.technicianId === tech.id)
            .reduce((sum, a) => sum + a.cost, 0)
    })).filter(d => d.value > 0);

    const COLORS = ['#3b82f6', '#16a34a', '#f97316', '#dc2626', '#6b21a8'];

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Dashboard</h1>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                <Card title="Total Clients" value={totalClients.toString()} />
                <Card title="Total Analyses" value={totalAnalyses.toString()} />
                <Card title="Total Revenue" value={`$${totalRevenue.toLocaleString()}`} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white p-6 rounded-lg shadow-md">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Analyses per Client</h2>
                    <ResponsiveContainer width="100%" height={300}>
                        <BarChart data={analysesPerClient}>
                            <CartesianGrid strokeDasharray="3 3" />
                            <XAxis dataKey="name" />
                            <YAxis allowDecimals={false} />
                            <Tooltip />
                            <Legend />
                            <Bar dataKey="Analyses" fill="#3b82f6" />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
                <div className="bg-white p-6 rounded-lg shadow-md">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Revenue per Technician</h2>
                     <ResponsiveContainer width="100%" height={300}>
                        <PieChart>
                            <Pie
                                data={costsPerTechnician}
                                cx="50%"
                                cy="50%"
                                labelLine={false}
                                outerRadius={110}
                                fill="#8884d8"
                                dataKey="value"
                                nameKey="name"
                                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                            >
                                {costsPerTechnician.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `$${value.toLocaleString()}`} />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

