import React, { useState, useEffect } from 'react';
import { AnalysisCost, Supplier, ProductType, Subtype } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { PlusIcon } from './icons/Icons';
import CodeBlock from './ui/CodeBlock';

const MOCK_SUPPLIERS: Supplier[] = [
    { id: 's1', name: 'ChemSupplies Co.', product: 'Reagents' },
    { id: 's2', name: 'LabGlass Inc.', product: 'Glassware' },
];
const MOCK_PRODUCTS: ProductType[] = [
    { id: 'p1', name: 'Cereal Grains' },
    { id: 'p2', name: 'Oilseeds' },
];
const MOCK_SUBTYPES: Subtype[] = [
    { id: 'st1', name: 'Corn Meal', productTypeId: 'p1' },
    { id: 'st2', name: 'Soybean Meal', productTypeId: 'p2' },
];

const initialCostFormState: Omit<AnalysisCost, 'id'> = {
    testName: '',
    cost: 0,
    method: ''
};

interface SettingsProps {
    analysisCosts: AnalysisCost[];
    onAddAnalysisCost: (cost: AnalysisCost) => void;
}

const Settings: React.FC<SettingsProps> = ({ analysisCosts, onAddAnalysisCost }) => {
    const [googleScriptUrl, setGoogleScriptUrl] = useState('');
    const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [isCostModalOpen, setIsCostModalOpen] = useState(false);
    const [costFormData, setCostFormData] = useState(initialCostFormState);

    useEffect(() => {
        const savedUrl = localStorage.getItem('googleScriptUrl');
        if (savedUrl) {
            setGoogleScriptUrl(savedUrl);
        }
    }, []);

    const handleSaveUrl = () => {
        localStorage.setItem('googleScriptUrl', googleScriptUrl);
        alert('URL saved successfully! Please refresh the page to load data.');
    };

    const handleTestConnection = async () => {
        if (!googleScriptUrl) {
            alert('Please enter a URL first.');
            return;
        }
        setTestStatus('testing');
        try {
            // Test POST for submitting data
            const postResponse = await fetch(googleScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ test: 'connection' }) 
            });
            if (!postResponse.ok) throw new Error(`POST Test Failed: Status ${postResponse.status}`);
            const postResult = await postResponse.json();
            if (postResult.status !== 'success') throw new Error(`POST Test Failed: ${postResult.message}`);

            // Test GET for reading data
            const getResponse = await fetch(googleScriptUrl);
            if (!getResponse.ok) throw new Error(`GET Test Failed: Status ${getResponse.status}`);
            const getResult = await getResponse.json();
            if (!getResult || typeof getResult !== 'object') throw new Error(`GET Test Failed: Invalid JSON response.`);


            setTestStatus('success');
        } catch (error) {
            console.error('Connection test failed:', error);
            setTestStatus('error');
        } finally {
            setTimeout(() => setTestStatus('idle'), 4000);
        }
    };

    const handleCloseCostModal = () => {
        setIsCostModalOpen(false);
        setCostFormData(initialCostFormState);
    };

    const handleCostFormChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value, type } = e.target;
        setCostFormData(prev => ({
            ...prev,
            [name]: type === 'number' ? parseFloat(value) : value
        }));
    };

    const handleCostFormSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (costFormData.testName && costFormData.method && costFormData.cost > 0) {
            const newCost: AnalysisCost = {
                id: `c${Date.now()}`,
                ...costFormData
            };
            onAddAnalysisCost(newCost);
            handleCloseCostModal();
        } else {
            alert('Please fill all fields correctly. Cost must be greater than 0.');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Settings</h1>

            <div className="space-y-8">
                {/* Google Sheets Integration */}
                <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Google Sheets Integration</h2>
                     <p className="text-gray-600 mt-2 mb-4">
                        Connect your Google Sheet as a database. This allows the app to load your clients, technicians, and costs, and also to submit new analysis results.
                     </p>
                    <div>
                        <label htmlFor="googleScriptUrl" className="block text-sm font-medium text-gray-700">Apps Script URL</label>
                        <input 
                            type="url" 
                            name="googleScriptUrl" 
                            id="googleScriptUrl" 
                            value={googleScriptUrl}
                            onChange={(e) => setGoogleScriptUrl(e.target.value)}
                            className={inputStyle}
                            placeholder="https://script.google.com/macros/s/..."
                        />
                    </div>
                    <div className="flex items-center space-x-2 mt-4">
                        <button onClick={handleSaveUrl} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                           Save URL & Refresh
                        </button>
                        <button onClick={handleTestConnection} className="bg-gray-600 text-white hover:bg-gray-700 font-bold py-2 px-4 rounded-lg transition-colors" disabled={testStatus === 'testing'}>
                           {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
                        </button>
                        {testStatus === 'success' && <span className="text-green-600 font-medium">Connection successful!</span>}
                        {testStatus === 'error' && <span className="text-red-600 font-medium">Connection failed. Check URL, script, and permissions.</span>}
                    </div>
                </div>

                {/* Setup Instructions */}
                 <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Setup Your Google Sheet as a Database</h2>
                     <div className="prose max-w-none mt-4 text-gray-800">
                        <p>Follow these steps to get your Google Sheet ready:</p>
                        <ol>
                            <li>Create a new Google Sheet. Note its ID from the URL (e.g., the long string in `.../d/SPREADSHEET_ID/edit`).</li>
                            <li>Create sheets (tabs) named exactly: <strong>Clients</strong>, <strong>Technicians</strong>, <strong>AnalysisCosts</strong>, and <strong>AnalysisResults</strong>.</li>
                            <li>In the first row of each sheet, add the required headers. For example, in 'Clients', add `id`, `name`, `contactPerson`, `email`, `phone`.</li>
                            <li>Go to `Extensions &gt; Apps Script`, paste the code below, replace `'YOUR_SPREADSHEET_ID'` with your actual ID, and click Deploy &gt; New Deployment.</li>
                            <li>Select 'Web app' as the type, execute as 'Me', and give access to 'Anyone'. Deploy and copy the Web app URL.</li>
                            <li>Paste that URL in the input field above and save.</li>
                        </ol>
                     </div>
                     <CodeBlock />
                </div>


                {/* Analysis Costs */}
                <div>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-2xl font-semibold text-gray-700">Analysis Costs</h2>
                        <button onClick={() => setIsCostModalOpen(true)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                            <PlusIcon /> <span className="ml-2">Add Cost</span>
                        </button>
                    </div>
                    <Table headers={['Test Name', 'Method', 'Cost ($)']} data={analysisCosts.map(c => [c.testName, c.method, c.cost.toFixed(2)])} />
                </div>
            </div>
            {isCostModalOpen && (
                <Modal onClose={handleCloseCostModal} title="Add New Analysis Cost">
                    <form onSubmit={handleCostFormSubmit}>
                        <div className="p-6 space-y-4">
                            <div>
                                <label htmlFor="testName" className="block text-sm font-medium text-gray-700">Test Name</label>
                                <input type="text" name="testName" id="testName" value={costFormData.testName} onChange={handleCostFormChange} required className={inputStyle} />
                            </div>
                            <div>
                                <label htmlFor="method" className="block text-sm font-medium text-gray-700">Analytical Method</label>
                                <input type="text" name="method" id="method" value={costFormData.method} onChange={handleCostFormChange} required className={inputStyle} placeholder="e.g., AOAC 984.13"/>
                            </div>
                            <div>
                                <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Cost ($)</label>
                                <input type="number" name="cost" id="cost" value={costFormData.cost} onChange={handleCostFormChange} required className={inputStyle} step="0.01" min="0"/>
                            </div>
                        </div>
                        <div className="flex justify-end p-4 bg-gray-50 border-t">
                             <button type="button" onClick={handleCloseCostModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                                Cancel
                            </button>
                            <button type="submit" className="bg-primary hover:bg-secondary text-white font-bold py-2 px-4 rounded-lg transition-colors">
                                Save Cost
                            </button>
                        </div>
                    </form>
                </Modal>
            )}
        </div>
    );
