  };
  const deleteAnalysis = (analysisId: string) => {
      setAnalyses(prev => prev.filter(a => a.id !== analysisId));
  };

  const addClient = (newClient: Client) => {
    setClients(prev => [...prev, newClient]);
  };
  const addTechnician = (newTechnician: Technician) => {
    setTechnicians(prev => [...prev, newTechnician]);
  }
  const addAnalysisCost = (newCost: AnalysisCost) => {
    setAnalysisCosts(prev => [...prev, newCost]);
  };

  const renderView = () => {
    if (loading) {
      return <Loader message="Loading data from Google Sheets..." />;
    }
    if (error && activeView !== 'settings') {
       return (
            <div className="text-center p-8">
