        return <ClientManagement clients={clients} onAddClient={addClient} />;
      case 'technicians':
        return <TechnicianManagement technicians={technicians} onAddTechnician={addTechnician} />;
      case 'newAnalysis':
        return <AnalysisRequest onAddAnalysis={addAnalysis} setActiveView={setActiveView} analysisCosts={analysisCosts} clients={clients} technicians={technicians} />;
      case 'analyses':
        return <AnalysisManagement analyses={analyses} onUpdateAnalysis={updateAnalysis} onDeleteAnalysis={deleteAnalysis} setActiveView={setActiveView} clients={clients} technicians={technicians} />;
