                            submitStatus === 'success' ? 'bg-green-600' :
                            'bg-primary hover:bg-secondary'
                        } text-white`}
                        disabled={submitStatus === 'submitting' || submitStatus === 'success' || selectedTests.length === 0 || !formData.clientId || !formData.technicianId}
                    >
                        {getButtonText()}
                    </button>
                </div>
            </form>
        </div>
    );
};

