import React, { useState } from 'react';

const appsScriptCode = `
/**
 * LabSys - Google Apps Script Backend
 * Author: Your World-Class Senior Frontend Engineer
 * Version: 2.2 (Full Data Sync)
 * Description: This script connects the LabSys web app to a Google Sheet.
 * It now loads all data including analysis results and correctly handles
 * numeric types for all relevant fields.
 */

// Sheet names must match the tabs in your Google Sheet exactly.
const CLIENTS_SHEET_NAME = "Clients";
const TECHNICIANS_SHEET_NAME = "Technicians";
const COSTS_SHEET_NAME = "AnalysisCosts";
const RESULTS_SHEET_NAME = "AnalysisResults";

/**
 * Handles GET requests. Triggered on app load to fetch initial data.
 */
function doGet(e) {
  try {
    const clientsData = getDataFromSheet(CLIENTS_SHEET_NAME);
    const techniciansData = getDataFromSheet(TECHNICIANS_SHEET_NAME);
    const costsData = getDataFromSheet(COSTS_SHEET_NAME);
    const resultsData = getDataFromSheet(RESULTS_SHEET_NAME);

    const response = {
      clients: arrayToObjects(clientsData),
      technicians: arrayToObjects(techniciansData),
      analysisCosts: arrayToObjects(costsData),
      analysisResults: arrayToObjects(resultsData)
    };

    return ContentService.createTextOutput(JSON.stringify(response))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    Logger.log("doGet Error: " + error.message);
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "doGet Error: " + error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Handles POST requests. Triggered when submitting data from the app.
 * Creates or updates records.
 */
function doPost(e) {
  // ROBUSTNESS CHECK: Prevent crash when run from the script editor.
  if (!e || !e.postData || !e.postData.contents) {
    Logger.log("doPost called without valid POST data. This is expected if run from the script editor.");
    return ContentService.createTextOutput(JSON.stringify({ 
        status: "info", 
        message: "Script is active. This function must be triggered by a POST request from the web app, not the editor." 
    })).setMimeType(ContentService.MimeType.JSON);
  }

  try {
    const data = JSON.parse(e.postData.contents);

    // Handles the "Test Connection" button click from the Settings page.
    if (data.test === 'connection') {
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Connection successful." }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(RESULTS_SHEET_NAME);
    if (!sheet) {
      throw new Error("Sheet '" + RESULTS_SHEET_NAME + "' not found.");
    }

    const headers = [
      'id', 'folio', 'receptionDate', 'deliveryDate', 'sampleName', 'product', 
      'subtype', 'clientId', 'technicianId', 'priority', 'status', 'cost', 
      'protein', 'fat', 'moisture', 'ash', 'fiber', 'starch'
    ];

    if (sheet.getLastRow() === 0) {
      sheet.appendRow(headers);
    }

    const rowData = headers.map(header => data[header] !== undefined ? data[header] : "");
    const sheetData = sheet.getDataRange().getValues();
    const idColumnIndex = sheetData[0].indexOf('id');
    let recordUpdated = false;

    if (idColumnIndex === -1 && sheet.getLastRow() > 0) {
      throw new Error("The 'id' column was not found in the AnalysisResults sheet. Please check the headers.");
    }

    if (idColumnIndex !== -1) {
        for (let i = 1; i < sheetData.length; i++) {
          if (sheetData[i][idColumnIndex] == data.id) {
            sheet.getRange(i + 1, 1, 1, headers.length).setValues([rowData]);
            recordUpdated = true;
            break;
          }
        }
    }

    if (!recordUpdated) {
      sheet.appendRow(rowData);
    }

    const message = recordUpdated ? "Data updated successfully" : "Data added successfully";
    return ContentService.createTextOutput(JSON.stringify({ status: "success", message: message }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    Logger.log("doPost Error: " + error.toString());
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "doPost Error: " + error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Helper function to read all data from a given sheet.
 */
function getDataFromSheet(sheetName) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet || sheet.getLastRow() < 1) return [];
  return sheet.getDataRange().getValues();
}

/**
 * Helper function to convert a 2D array from a sheet into an array of objects.
 */
function arrayToObjects(data) {
  if (data.length < 2) return [];
  const headers = data[0].map(String);
  const numericHeaders = ['cost', 'protein', 'fat', 'moisture', 'ash', 'fiber', 'starch'];
  const objects = [];

  for (let i = 1; i < data.length; i++) {
    const obj = {};
    for (let j = 0; j < headers.length; j++) {
      const header = headers[j];
      let value = data[i][j];

      if (numericHeaders.includes(header) && !isNaN(value) && value !== '') {
        value = Number(value);
      }
      obj[header] = value;
    }
    objects.push(obj);
  }
  return objects;
}
`.trim();

const CodeBlock: React.FC = () => {
