    analysisCosts: AnalysisCost[];
    onAddAnalysisCost: (cost: AnalysisCost) => void;
}

const Settings: React.FC<SettingsProps> = ({ analysisCosts, onAddAnalysisCost }) => {
    const [googleScriptUrl, setGoogleScriptUrl] = useState('');
    const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [isCostModalOpen, setIsCostModalOpen] = useState(false);
    const [costFormData, setCostFormData] = useState(initialCostFormState);

    useEffect(() => {
        const savedUrl = localStorage.getItem('googleScriptUrl');
        if (savedUrl) {
            setGoogleScriptUrl(savedUrl);
        }
    }, []);

    const handleSaveUrl = () => {
        localStorage.setItem('googleScriptUrl', googleScriptUrl);
        alert('URL saved successfully! Please refresh the page to load data.');
    };

    const handleTestConnection = async () => {
        if (!googleScriptUrl) {
            alert('Please enter a URL first.');
            return;
        }
        setTestStatus('testing');
        try {
            // Test 1: GET request
            const getResponse = await fetch(googleScriptUrl);
            if (!getResponse.ok) throw new Error(`GET Test Failed: Status ${getResponse.status}`);
            const getResult = await getResponse.json();
            if (!getResult || typeof getResult !== 'object' || !getResult.clients) throw new Error(`GET Test Failed: Invalid JSON response.`);

            // Test 2: POST request using URLSearchParams to avoid CORS preflight
            const formData = new URLSearchParams();
            formData.append('payload', JSON.stringify({ action: 'testConnection' }));

            const postResponse = await fetch(googleScriptUrl, {
                method: 'POST',
                body: formData
            });
            if (!postResponse.ok) throw new Error(`POST Test Failed: Status ${postResponse.status}`);
            const postResult = await postResponse.json();
            if (postResult.status !== 'success') throw new Error(`POST Test Failed: ${postResult.message}`);

            setTestStatus('success');
        } catch (error) {
            console.error('Connection test failed:', error);
            setTestStatus('error');
        } finally {
            setTimeout(() => setTestStatus('idle'), 5000);
        }
    };

    const handleCloseCostModal = () => {
        setIsCostModalOpen(false);
        setCostFormData(initialCostFormState);
    };

