import CodeBlock from './ui/CodeBlock';

const initialCostFormState: Omit<AnalysisCost, 'id'> = {
    testName: '',
    cost: 0,
    method: ''
};

// These are the only tests the system can map to specific result fields in the database.
const MAPPABLE_TESTS = [
    'Protein (Kjeldahl)',
    'Fat (Soxlet)',
    'Moisture (Oven)',
    'Fiber (Crude)',
    'Ash (Muffle Furnace)',
    'Starch (Polarimetry)',
];

interface SettingsProps {
    analysisCosts: AnalysisCost[];
    onAddAnalysisCost: (cost: AnalysisCost) => void;
}

const Settings: React.FC<SettingsProps> = ({ analysisCosts, onAddAnalysisCost }) => {
    const [googleScriptUrl, setGoogleScriptUrl] = useState('');
    const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [isCostModalOpen, setIsCostModalOpen] = useState(false);
    const [costFormData, setCostFormData] = useState(initialCostFormState);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
    const [submitError, setSubmitError] = useState<string | null>(null);

    useEffect(() => {
        const savedUrl = localStorage.getItem('googleScriptUrl');
        if (savedUrl) {
            setGoogleScriptUrl(savedUrl);
        }
    }, []);

    const handleSaveUrl = () => {
        localStorage.setItem('googleScriptUrl', googleScriptUrl);
        alert('URL saved successfully! Please refresh the page to load data.');
    };

    const handleTestConnection = async () => {
        if (!googleScriptUrl) {
            alert('Please enter a URL first.');
            return;
        }
        setTestStatus('testing');
        try {
            // Test 1: GET request
            const getResponse = await fetch(googleScriptUrl);
            if (!getResponse.ok) throw new Error(`GET Test Failed: Status ${getResponse.status}`);
            const getResult = await getResponse.json();
            if (!getResult || typeof getResult !== 'object' || !getResult.clients) throw new Error(`GET Test Failed: Invalid JSON response.`);

            // Test 2: POST request using URLSearchParams to avoid CORS preflight
            const postData = new URLSearchParams();
            const requestPayload = { action: 'testConnection', targetSheet: 'any', payload: {} };
            postData.append('payload', JSON.stringify(requestPayload));

            const postResponse = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData
            });
            if (!postResponse.ok) throw new Error(`POST Test Failed: Status ${postResponse.status}`);
            const postResult = await postResponse.json();
            if (postResult.status !== 'success') throw new Error(`POST Test Failed: ${postResult.message}`);

            setTestStatus('success');
        } catch (error) {
            console.error('Connection test failed:', error);
            setTestStatus('error');
        } finally {
            setTimeout(() => setTestStatus('idle'), 5000);
        }
    };

    const handleCloseCostModal = () => {
        setIsCostModalOpen(false);
        setCostFormData(initialCostFormState);
        setSubmitStatus('idle');
        setSubmitError(null);
    };

    const handleCostFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        setCostFormData(prev => ({
            ...prev,
            [name]: type === 'number' ? parseFloat(value) : value
        }));
    };

    const handleCostFormSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (!costFormData.testName || !costFormData.method || costFormData.cost <= 0) {
            alert('Please fill all fields correctly. Cost must be greater than 0.');
            return;
        }

        setSubmitStatus('submitting');
        setSubmitError(null);

        const newCost: AnalysisCost = {
            id: `c${Date.now()}`,
            ...costFormData
        };

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            setSubmitError('Google Sheets URL not configured.');
            setSubmitStatus('error');
            return;
        }

        try {
            const requestPayload = { 
                action: 'create', 
                targetSheet: 'AnalysisCosts', 
                payload: newCost
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                onAddAnalysisCost(newCost);
                setSubmitStatus('success');
                setTimeout(() => handleCloseCostModal(), 1000);
            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }

        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : "An unknown error occurred.";
            setSubmitError(`Failed to save cost: ${errorMessage}.`);
            setSubmitStatus('error');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Saving...';
            case 'success': return 'Saved!';
            case 'error': return 'Retry Save';
            default: return 'Save Cost';
        }
    }

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Settings</h1>

            <div className="space-y-8">
                <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Google Sheets Integration</h2>
                     <p className="text-gray-600 mt-2 mb-4">
                        Connect your Google Sheet as a database. This allows the app to load your clients, technicians, and costs, and also to submit new analysis results.
                     </p>
                    <div>
                        <label htmlFor="googleScriptUrl" className="block text-sm font-medium text-gray-700">Apps Script URL</label>
                        <input 
                            type="url" 
                            name="googleScriptUrl" 
                            id="googleScriptUrl" 
                            value={googleScriptUrl}
                            onChange={(e) => setGoogleScriptUrl(e.target.value)}
                            className={inputStyle}
                            placeholder="https://script.google.com/macros/s/..."
                        />
                    </div>
                    <div className="flex items-center space-x-2 mt-4">
                        <button onClick={handleSaveUrl} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                           Save URL
                        </button>
                        <button onClick={handleTestConnection} className="bg-gray-600 text-white hover:bg-gray-700 font-bold py-2 px-4 rounded-lg transition-colors" disabled={testStatus === 'testing'}>
                           {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
                        </button>
                        {testStatus === 'success' && <span className="text-green-600 font-medium">Connection successful!</span>}
                        {testStatus === 'error' && <span className="text-red-600 font-medium">Connection failed. Check URL/permissions and browser console for CORS errors.</span>}
                    </div>
                </div>

                 <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Setup Your Google Sheet as a Database</h2>
                     <div className="prose max-w-none mt-4 text-gray-800">
                        <p>Follow these steps to get your Google Sheet ready:</p>
                        <ol className="list-decimal pl-5 space-y-2">
                            <li>Create a new Google Sheet.</li>
                            <li>Create four tabs named exactly: <strong>Clients</strong>, <strong>Technicians</strong>, <strong>AnalysisCosts</strong>, and <strong>AnalysisResults</strong>.</li>
                            <li>In the first row of each sheet, add the required headers.
                                <ul className="list-disc pl-5 mt-1">
                                    <li><strong>Clients:</strong> id, name, contactPerson, email, phone</li>
                                    <li><strong>Technicians:</strong> id, name, specialty, hireDate</li>
                                    <li><strong>AnalysisCosts:</strong> id, testName, cost, method</li>
                                    <li><strong>AnalysisResults:</strong> id, folio, receptionDate, deliveryDate, sampleName, product, subtype, clientId, technicianId, priority, status, cost, requestedTests, protein, fat, moisture, ash, fiber, starch</li>
                                </ul>
                            </li>
                            <li>Go to `Extensions &gt; Apps Script`, paste the code below, and save the project.</li>
                            <li>Click `Deploy &gt; New Deployment`. Select `Web app` as the type.</li>
                            <li>In the dialog, set `Execute as` to `Me` and `Who has access` to `Anyone`.</li>
                            <li>Click `Deploy`. Authorize the script's permissions when prompted.</li>
                            <li>Copy the `Web app URL` provided and paste it into the input field above.</li>
                        </ol>
                        <div className="mt-4 p-4 bg-yellow-100 border-l-4 border-yellow-500 text-yellow-800 rounded-r-lg">
                            <h4 className="font-bold">Troubleshooting Connection Errors</h4>
                            <p>The most common error is a "CORS" or "Network" error. This happens because Google Scripts can block certain types of web requests. The code provided here is specifically designed to avoid this issue. If you still see an error like "Sheet not found", it means the name of the tab in your Google Sheet does not <strong className="font-extrabold">exactly</strong> match the name required (e.g., "AnalysisResults"). Names are case-sensitive. After any script change, you must re-deploy: select <strong>Deploy &gt; Manage Deployments</strong>, edit your deployment, choose a <strong>New version</strong>, and click <strong>Deploy</strong>.</p>
                        </div>
                     </div>
                     <CodeBlock />
                </div>

                <div>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-2xl font-semibold text-gray-700">Analysis Costs</h2>
                        <button onClick={() => setIsCostModalOpen(true)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                            <PlusIcon /> <span className="ml-2">Add Cost</span>
                        </button>
                    </div>
                    <Table headers={['Test Name', 'Method', 'Cost ($)']} data={analysisCosts.map(c => [c.testName, c.method, (typeof c.cost === 'number' ? c.cost : 0).toFixed(2)])} />
                </div>
            </div>
            {isCostModalOpen && (
                <Modal onClose={handleCloseCostModal} title="Add New Analysis Cost">
                    <form onSubmit={handleCostFormSubmit}>
                        <div className="p-6 space-y-4">
                            <div>
                                <label htmlFor="testName" className="block text-sm font-medium text-gray-700">Test Name</label>
                                <select 
                                    name="testName" 
                                    id="testName" 
                                    value={costFormData.testName} 
                                    onChange={handleCostFormChange} 
                                    required 
                                    className={inputStyle}
                                >
                                    <option value="" disabled>Select a standard test</option>
                                    {MAPPABLE_TESTS.map(name => <option key={name} value={name}>{name}</option>)}
                                </select>
                                <p className="mt-2 text-xs text-gray-500">
                                    Only these standard tests can have numeric results recorded in the system.
                                </p>
                            </div>
                            <div>
                                <label htmlFor="method" className="block text-sm font-medium text-gray-700">Analytical Method</label>
                                <input type="text" name="method" id="method" value={costFormData.method} onChange={handleCostFormChange} required className={inputStyle} placeholder="e.g., AOAC 984.13"/>
                            </div>
                            <div>
                                <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Cost ($)</label>
                                <input type="number" name="cost" id="cost" value={costFormData.cost} onChange={handleCostFormChange} required className={inputStyle} step="0.01" min="0"/>
                            </div>
                             {submitStatus === 'error' && submitError && (
                                <div className="text-xs text-center p-2 bg-red-50 text-red-700 rounded-md">{submitError}</div>
