import React, { useState } from 'react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Analysis, Client, Technician, View, AnalysisStatus } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { DownloadIcon, SheetIcon, PlusIcon } from './icons/Icons';

const testNameToPropertyMap: { [key: string]: keyof Analysis } = {
    'Protein': 'protein',
    'Fat': 'fat',
    'Moisture': 'moisture',
    'Fiber': 'fiber',
    'Ash': 'ash',
    'Starch': 'starch',
};

/**
 * Intelligently maps a user-defined test name from the sheet to the system's canonical test data.
 * It works by checking if the sheet test name contains the base name of a canonical test (e.g., "Protein"), ignoring case.
 * @param testNameFromSheet The test name as it appears in the Google Sheet.
 * @returns An object with the canonical name and property name, or null if no match is found.
 */
const getTestMapping = (testNameFromSheet: string): { canonicalName: string; propName: keyof Analysis } | null => {
    const lowerCaseTestName = testNameFromSheet.toLowerCase();

    const canonicalName = Object.keys(testNameToPropertyMap).find(key => {
        const baseName = key.split('(')[0].trim().toLowerCase();
        return lowerCaseTestName.includes(baseName);
    });

    if (canonicalName) {
        return {
            canonicalName,
            propName: testNameToPropertyMap[canonicalName],
        };
    }

    return null;
};


const statusOptions: AnalysisStatus[] = ['Received', 'In Progress', 'Completed', 'Cancelled'];

interface AnalysisManagementProps {
    analyses: Analysis[];
    clients: Client[];
    technicians: Technician[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ analyses, clients, technicians, reloadData, setActiveView }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);
    const [modalFormData, setModalFormData] = useState<Partial<Analysis>>({});
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

    const handleEdit = (index: number) => {
        const analysisToEdit = analyses[index];
        setEditingAnalysis(analysisToEdit);
        setModalFormData(analysisToEdit);
        setIsModalOpen(true);
    };

    const handleDelete = async (index: number) => {
        if (window.confirm('Are you sure you want to delete this analysis? This will also remove it from your Google Sheet.')) {
            const analysisToDelete = analyses[index];
            const googleScriptUrl = localStorage.getItem('googleScriptUrl');

            if (!googleScriptUrl) {
                alert('Google Sheets URL not configured. Please set it in Settings.');
                return;
            }

            try {
                const requestPayload = {
                    action: 'delete',
                    targetSheet: 'AnalysisResults',
                    payload: { id: analysisToDelete.id }
                };
                const postData = new URLSearchParams();
                postData.append('payload', JSON.stringify(requestPayload));

                const response = await fetch(googleScriptUrl, {
                    method: 'POST',
                    body: postData,
                });
                const result = await response.json();

                if (result.status === 'success') {
                    await reloadData();
                    alert('Analysis deleted successfully.');
                } else {
                    throw new Error(result.message || 'Unknown error from Google Script.');
                }
            } catch (error) {
                console.error('Failed to delete from Google Sheets:', error);
                alert(`Failed to delete analysis. Error: ${error instanceof Error ? error.message : String(error)}`);
            }
        }
    };

    const handlePrint = (index: number) => {
        handlePrintReport(analyses[index]);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingAnalysis(null);
        setSubmitStatus('idle');
    };

    const handleModalFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setModalFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleModalResultChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        const numericValue = value === '' ? undefined : parseFloat(value);
        setModalFormData(prev => ({...prev, [name]: numericValue }));
    }

    const handleSaveAndSubmit = async () => {
        if (!editingAnalysis || !modalFormData) return;

        setSubmitStatus('submitting');

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            alert('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        const updatedAnalysisData: Analysis = {
            ...editingAnalysis,
            ...modalFormData,
        };

        const analysisPayload = { ...updatedAnalysisData };

        Object.values(testNameToPropertyMap).forEach(prop => {
            if (!analysisPayload.hasOwnProperty(prop)) {
                (analysisPayload as any)[prop] = null;
            }
        });

        try {
            const requestPayload = {
                action: 'update',
                targetSheet: 'AnalysisResults',
                payload: analysisPayload
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                setSubmitStatus('success');
                setTimeout(async () => {
                    await reloadData();
                    handleCloseModal();
                }, 1500);
            } else {
                 throw new Error(result.message || 'Unknown error from Google Script.');
            }
        } catch (error) {
             console.error('Failed to submit to Google Sheets:', error);
             alert(`Failed to submit data. Error: ${error instanceof Error ? error.message : String(error)}`);
             setSubmitStatus('error');
        }
    }

    const headers = ['Folio', 'Reception', 'Delivery', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status'];
    const dataRows = analyses.map(a => [
        a.folio, 
        a.receptionDate,
        a.deliveryDate ?? 'N/A',
        a.sampleName,
        a.product,
        clients.find(c => c.id === a.clientId)?.name ?? 'Unknown',
        technicians.find(t => t.id === a.technicianId)?.name ?? 'Unknown',
        a.priority,
        a.status,
    ]);

    const handleDownloadPdf = () => {
        const doc = new jsPDF();
        doc.text("Analysis Report", 14, 15);
        autoTable(doc, {
            head: [headers],
            body: dataRows,
            startY: 20,
            theme: 'grid',
            headStyles: { fillColor: [30, 64, 175] },
        });
        doc.save('analysis-report.pdf');
    };

    const handleExportCSV = () => {
        const csvHeaders = ['Folio', 'Reception Date', 'Delivery Date', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status', 'Cost ($)', 'Requested Tests', 'Protein (%)', 'Fat (%)', 'Moisture (%)', 'Fiber (%)', 'Ash (%)', 'Starch (%)'];

        const escapeCsvCell = (cell: any): string => {
            const strCell = String(cell ?? '');
            if (strCell.includes(',') || strCell.includes('"') || strCell.includes('\n')) {
                return `"${strCell.replace(/"/g, '""')}"`;
            }
            return strCell;
        };

        const csvRows = analyses.map(a => {
            const clientName = clients.find(c => c.id === a.clientId)?.name ?? 'Unknown';
            const technicianName = technicians.find(t => t.id === a.technicianId)?.name ?? 'Unknown';
            return [
                a.folio, a.receptionDate, a.deliveryDate, a.sampleName, a.product,
                clientName, technicianName, a.priority, a.status, a.cost,
                (a.requestedTests || []).join('; '),
                a.protein, a.fat, a.moisture, a.fiber, a.ash, a.starch
            ].map(escapeCsvCell).join(',');
        });

        const csvContent = [csvHeaders.join(','), ...csvRows].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", "analysis-report.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handlePrintReport = (analysis: Analysis) => {
        const doc = new jsPDF();
        const client = clients.find(c => c.id === analysis.clientId);

        doc.setFontSize(20);
        doc.text("Analysis Report", 105, 15, { align: 'center' });
        doc.setFontSize(12);
        doc.text(`Folio: ${analysis.folio}`, 14, 30);
        doc.text(`Client: ${client?.name ?? 'Unknown'}`, 14, 37);
        doc.text(`Sample: ${analysis.sampleName}`, 14, 44);
        doc.text(`Reception Date: ${analysis.receptionDate}`, 150, 30);
        doc.text(`Delivery Date: ${analysis.deliveryDate ?? 'N/A'}`, 150, 37);

        const tableBody = (analysis.requestedTests || [])
            .map(testName => {
                const mapping = getTestMapping(testName);
                if (!mapping) return null;

                const result = analysis[mapping.propName];
                const displayName = mapping.canonicalName.split('(')[0].trim();
                return [displayName, typeof result === 'number' ? result.toFixed(2) : 'N/A'];
            })
            .filter((row): row is [string, string] => row !== null);

        autoTable(doc, {
            startY: 55,
            head: [['Parameter', 'Result (%)']],
            body: tableBody,
            theme: 'grid',
        });

        const technician = technicians.find(t => t.id === analysis.technicianId);
        doc.text(`Technician: ${technician?.name ?? 'Unknown'}`, 14, (doc as any).lastAutoTable.finalY + 20);

        doc.save(`report-${analysis.folio}.pdf`);
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold text-gray-800">Analysis Management</h1>
                <div className="flex items-center space-x-2">
                    <button onClick={handleDownloadPdf} className="bg-white text-gray-700 hover:bg-gray-100 border border-gray-300 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <DownloadIcon /> <span className="ml-2">Download PDF</span>
                    </button>
                    <button onClick={handleExportCSV} className="bg-green-600 text-white hover:bg-green-700 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <SheetIcon /> <span className="ml-2">Export CSV</span>
                    </button>
                    <button onClick={() => setActiveView('newAnalysis')} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <PlusIcon /> <span className="ml-2">New Analysis</span>
                    </button>
                </div>
            </div>
            <Table headers={headers} data={dataRows} onEdit={handleEdit} onDelete={handleDelete} onPrint={handlePrint} />
            {isModalOpen && editingAnalysis && (
                <Modal onClose={handleCloseModal} title={`Edit Analysis - ${editingAnalysis.folio}`}>
                    <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label htmlFor="deliveryDate" className="block text-sm font-medium text-gray-700">Delivery Date</label>
                            <input type="date" name="deliveryDate" id="deliveryDate" value={modalFormData.deliveryDate?.split('T')[0] || ''} onChange={handleModalFormChange} className={inputStyle} />
                        </div>
                        <div>
                            <label htmlFor="status" className="block text-sm font-medium text-gray-700">Status</label>
                            <select name="status" id="status" value={modalFormData.status} onChange={handleModalFormChange} className={inputStyle}>
                                {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                      </div>
                      <div className="border-t pt-4">
                        <h3 className="text-lg font-medium text-gray-800 mb-2">Analysis Results</h3>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                            {(editingAnalysis.requestedTests || []).map(testName => {
                                const mapping = getTestMapping(testName);
                                if (!mapping) return null;

                                const { canonicalName, propName } = mapping;
                                const displayName = canonicalName.split('(')[0].trim();

                                return (
                                    <div key={propName}>
                                        <label htmlFor={propName} className="block text-sm font-medium text-gray-700">{displayName} (%)</label>
                                        <input 
                                            type="number" 
                                            id={propName}
                                            name={propName}
                                            value={modalFormData[propName] ?? ''}
                                            onChange={handleModalResultChange}
                                            className={inputStyle}
                                            placeholder="0.00"
                                            step="0.01"
                                        />
                                    </div>
                                )
                            })}
                        </div>
                      </div>
                    </div>
                    <div className="flex justify-end p-4 bg-gray-50 border-t">
                        <button onClick={handleCloseModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                            Cancel
                        </button>
                        <button onClick={handleSaveAndSubmit} disabled={submitStatus === 'submitting' || submitStatus === 'success'} className={`font-bold py-2 px-4 rounded-lg transition-colors text-white ${
                             submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' : 
                             submitStatus === 'success' ? 'bg-green-600' : 
                             submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                             'bg-primary hover:bg-secondary'
                        }`}>
                            {submitStatus === 'submitting' ? 'Saving...' : submitStatus === 'success' ? 'Saved!' : 'Save & Submit to Sheet'}
                        </button>
                    </div>
                </Modal>
            )}
        </div>
    );
};

export default AnalysisManagement;

import React, { useState, useEffect } from 'react';
import { AnalysisCost } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { PlusIcon } from './icons/Icons';
import CodeBlock from './ui/CodeBlock';

const initialCostFormState: Omit<AnalysisCost, 'id'> = {
    testName: '',
    cost: 0,
    method: ''
};

// These are the only tests the system can map to specific result fields in the database.
const MAPPABLE_TESTS = [
    'Protein',
    'Fat',
    'Moisture',
    'Fiber',
    'Ash',
    'Starch',
];

interface SettingsProps {
    analysisCosts: AnalysisCost[];
    reloadData: () => Promise<void>;
}

const Settings: React.FC<SettingsProps> = ({ analysisCosts, reloadData }) => {
    const [googleScriptUrl, setGoogleScriptUrl] = useState('');
    const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [isCostModalOpen, setIsCostModalOpen] = useState(false);
    const [costFormData, setCostFormData] = useState(initialCostFormState);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
    const [submitError, setSubmitError] = useState<string | null>(null);

    useEffect(() => {
        const savedUrl = localStorage.getItem('googleScriptUrl');
        if (savedUrl) {
            setGoogleScriptUrl(savedUrl);
        }
    }, []);

    const handleSaveUrl = () => {
        localStorage.setItem('googleScriptUrl', googleScriptUrl);
        alert('URL saved successfully! Please refresh the page to load data.');
    };

    const handleTestConnection = async () => {
        if (!googleScriptUrl) {
            alert('Please enter a URL first.');
            return;
        }
        setTestStatus('testing');
        try {
            // Test 1: GET request
            const getResponse = await fetch(googleScriptUrl);
            if (!getResponse.ok) throw new Error(`GET Test Failed: Status ${getResponse.status}`);
            const getResult = await getResponse.json();
            if (!getResult || typeof getResult !== 'object' || !getResult.clients) throw new Error(`GET Test Failed: Invalid JSON response.`);

            // Test 2: POST request using URLSearchParams to avoid CORS preflight
            const postData = new URLSearchParams();
            const requestPayload = { action: 'testConnection', targetSheet: 'any', payload: {} };
            postData.append('payload', JSON.stringify(requestPayload));

            const postResponse = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData
            });
            if (!postResponse.ok) throw new Error(`POST Test Failed: Status ${postResponse.status}`);
            const postResult = await postResponse.json();
            if (postResult.status !== 'success') throw new Error(`POST Test Failed: ${postResult.message}`);

            setTestStatus('success');
        } catch (error) {
            console.error('Connection test failed:', error);
            setTestStatus('error');
        } finally {
            setTimeout(() => setTestStatus('idle'), 5000);
        }
    };

    const handleCloseCostModal = () => {
        setIsCostModalOpen(false);
        setCostFormData(initialCostFormState);
        setSubmitStatus('idle');
        setSubmitError(null);
    };

    const handleCostFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        setCostFormData(prev => ({
            ...prev,
            [name]: type === 'number' ? parseFloat(value) : value
        }));
    };

    const handleCostFormSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (!costFormData.testName || !costFormData.method || costFormData.cost <= 0) {
            alert('Please fill all fields correctly. Cost must be greater than 0.');
            return;
        }

        setSubmitStatus('submitting');
        setSubmitError(null);

        const newCost: AnalysisCost = {
            id: `c${Date.now()}`,
            ...costFormData
        };

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            setSubmitError('Google Sheets URL not configured.');
            setSubmitStatus('error');
            return;
        }

        try {
            const requestPayload = { 
                action: 'create', 
                targetSheet: 'AnalysisCosts', 
                payload: newCost
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                await reloadData();
                setSubmitStatus('success');
                setTimeout(() => handleCloseCostModal(), 1000);
            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }

        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : "An unknown error occurred.";
            setSubmitError(`Failed to save cost: ${errorMessage}.`);
            setSubmitStatus('error');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Saving...';
            case 'success': return 'Saved!';
            case 'error': return 'Retry Save';
            default: return 'Save Cost';
        }
    }

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Settings</h1>

            <div className="space-y-8">
                <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Google Sheets Integration</h2>
                     <p className="text-gray-600 mt-2 mb-4">
                        Connect your Google Sheet as a database. This allows the app to load your clients, technicians, and costs, and also to submit new analysis results.
                     </p>
                    <div>
                        <label htmlFor="googleScriptUrl" className="block text-sm font-medium text-gray-700">Apps Script URL</label>
                        <input 
                            type="url" 
                            name="googleScriptUrl" 
                            id="googleScriptUrl" 
                            value={googleScriptUrl}
                            onChange={(e) => setGoogleScriptUrl(e.target.value)}
                            className={inputStyle}
                            placeholder="https://script.google.com/macros/s/..."
                        />
                    </div>
                    <div className="flex items-center space-x-2 mt-4">
                        <button onClick={handleSaveUrl} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                           Save URL
                        </button>
                        <button onClick={handleTestConnection} className="bg-gray-600 text-white hover:bg-gray-700 font-bold py-2 px-4 rounded-lg transition-colors" disabled={testStatus === 'testing'}>
                           {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
                        </button>
                        {testStatus === 'success' && <span className="text-green-600 font-medium">Connection successful!</span>}
                        {testStatus === 'error' && <span className="text-red-600 font-medium">Connection failed. Check URL/permissions and browser console for CORS errors.</span>}
                    </div>
                </div>

                 <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Setup Your Google Sheet as a Database</h2>
                     <div className="prose max-w-none mt-4 text-gray-800">
                        <p>Follow these steps to get your Google Sheet ready:</p>
                        <ol className="list-decimal pl-5 space-y-2">
                            <li>Create a new Google Sheet.</li>
                            <li>Create four tabs named exactly: <strong>Clients</strong>, <strong>Technicians</strong>, <strong>AnalysisCosts</strong>, and <strong>AnalysisResults</strong>.</li>
                            <li>In the first row of each sheet, add the required headers.
                                <ul className="list-disc pl-5 mt-1">
                                    <li><strong>Clients:</strong> id, name, contactPerson, email, phone</li>
                                    <li><strong>Technicians:</strong> id, name, specialty, hireDate</li>
                                    <li><strong>AnalysisCosts:</strong> id, testName, cost, method</li>
                                    <li><strong>AnalysisResults:</strong> id, folio, receptionDate, deliveryDate, sampleName, product, subtype, clientId, technicianId, priority, status, cost, requestedTests, protein, fat, moisture, ash, fiber, starch</li>
                                </ul>
                            </li>
                            <li>Go to `Extensions &gt; Apps Script`, paste the code below, and save the project.</li>
                            <li>Click `Deploy &gt; New Deployment`. Select `Web app` as the type.</li>
                            <li>In the dialog, set `Execute as` to `Me` and `Who has access` to `Anyone`.</li>
                            <li>Click `Deploy`. Authorize the script's permissions when prompted.</li>
                            <li>Copy the `Web app URL` provided and paste it into the input field above.</li>
                        </ol>
                        <div className="mt-4 p-4 bg-yellow-100 border-l-4 border-yellow-500 text-yellow-800 rounded-r-lg">
                            <h4 className="font-bold">Troubleshooting Connection Errors</h4>
                            <p>The most common error is a "CORS" or "Network" error. This happens because Google Scripts can block certain types of web requests. The code provided here is specifically designed to avoid this issue. If you still see an error like "Sheet not found", it means the name of the tab in your Google Sheet does not <strong className="font-extrabold">exactly</strong> match the name required (e.g., "AnalysisResults"). Names are case-sensitive. After any script change, you must re-deploy: select <strong>Deploy &gt; Manage Deployments</strong>, edit your deployment, choose a <strong>New version</strong>, and click <strong>Deploy</strong>.</p>
                        </div>
                     </div>
                     <CodeBlock />
                </div>

                <div>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-2xl font-semibold text-gray-700">Analysis Costs</h2>
                        <button onClick={() => setIsCostModalOpen(true)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                            <PlusIcon /> <span className="ml-2">Add Cost</span>
                        </button>
                    </div>
                    <Table headers={['Test Name', 'Method', 'Cost ($)']} data={analysisCosts.map(c => [c.testName, c.method, (typeof c.cost === 'number' ? c.cost : 0).toFixed(2)])} />
                </div>
            </div>
            {isCostModalOpen && (
                <Modal onClose={handleCloseCostModal} title="Add New Analysis Cost">
                    <form onSubmit={handleCostFormSubmit}>
                        <div className="p-6 space-y-4">
                            <div>
                                <label htmlFor="testName" className="block text-sm font-medium text-gray-700">Test Name</label>
                                <select 
                                    name="testName" 
                                    id="testName" 
                                    value={costFormData.testName} 
                                    onChange={handleCostFormChange} 
                                    required 
                                    className={inputStyle}
                                >
                                    <option value="" disabled>Select a standard test</option>
                                    {MAPPABLE_TESTS.map(name => <option key={name} value={name}>{name}</option>)}
                                </select>
                                <p className="mt-2 text-xs text-gray-500">
                                    Only these standard tests can have numeric results recorded in the system.
                                </p>
                            </div>
                            <div>
                                <label htmlFor="method" className="block text-sm font-medium text-gray-700">Analytical Method</label>
                                <input type="text" name="method" id="method" value={costFormData.method} onChange={handleCostFormChange} required className={inputStyle} placeholder="e.g., AOAC 984.13"/>
                            </div>
                            <div>
                                <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Cost ($)</label>
                                <input type="number" name="cost" id="cost" value={costFormData.cost} onChange={handleCostFormChange} required className={inputStyle} step="0.01" min="0"/>
                            </div>
                             {submitStatus === 'error' && submitError && (
                                <div className="text-xs text-center p-2 bg-red-50 text-red-700 rounded-md">{submitError}</div>
                            )}
                        </div>
                        <div className="flex justify-end p-4 bg-gray-50 border-t">
                             <button type="button" onClick={handleCloseCostModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                                Cancel
                            </button>
                            <button type="submit" className={`font-bold py-2 px-4 rounded-lg transition-colors text-white ${
                                submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' :
                                submitStatus === 'success' ? 'bg-green-600' :
                                submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                                'bg-primary hover:bg-secondary'
                            }`} disabled={submitStatus === 'submitting' || submitStatus === 'success'}>
                                {getButtonText()}
                            </button>
                        </div>
                    </form>
                </Modal>
            )}
        </div>
    );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { Analysis, Client, Technician, AnalysisPriority, AnalysisCost, View } from '../types';

const MOCK_PRODUCTS: string[] = [ 'Corn', 'Soybean Meal', 'Wheat Midds', 'Fishmeal', 'DDGS' ];
const priorityOptions: AnalysisPriority[] = ['Normal', 'Urgent', 'Low'];

interface AnalysisRequestProps {
    clients: Client[];
    technicians: Technician[];
    analysisCosts: AnalysisCost[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

let folioCounter = new Date().getMilliseconds();

const generateFolio = (): string => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const sequence = String(folioCounter++).padStart(4, '0');
    return `${year}${month}${sequence}`;
};

const initialFormData = {
    folio: '',
    receptionDate: new Date().toISOString().split('T')[0],
    sampleName: '',
    product: '',
    subtype: '',
    clientId: '',
    technicianId: '',
    priority: 'Normal' as AnalysisPriority,
};

const AnalysisRequest: React.FC<AnalysisRequestProps> = ({ reloadData, setActiveView, analysisCosts, clients, technicians }) => {
    const [formData, setFormData] = useState(initialFormData);
    const [selectedTests, setSelectedTests] = useState<AnalysisCost[]>([]);
    const [totalCost, setTotalCost] = useState(0);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
    const [submitError, setSubmitError] = useState<string | null>(null);

    useEffect(() => {
        setFormData(prev => ({ ...prev, folio: generateFolio() }));
    }, []);

    useEffect(() => {
        const newCost = selectedTests.reduce((sum, test) => sum + (Number(test.cost) || 0), 0);
        setTotalCost(newCost);
    }, [selectedTests]);

    const handleTestSelection = (test: AnalysisCost, isChecked: boolean) => {
        if (isChecked) {
            setSelectedTests(prev => [...prev, test]);
        } else {
            setSelectedTests(prev => prev.filter(t => t.id !== test.id));
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
         if (selectedTests.length === 0 || !formData.clientId || !formData.technicianId) {
            alert("Please select a client, technician, and at least one test.");
            return;
        }
        setSubmitStatus('submitting');
        setSubmitError(null);

        const newAnalysis: Analysis = {
            ...formData,
            id: `an${Date.now()}`,
            cost: totalCost,
            requestedTests: selectedTests.map(t => t.testName),
            status: 'Received',
        };

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            setSubmitError('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        try {
            const requestPayload = { 
                action: 'create', 
                targetSheet: 'AnalysisResults', 
                payload: newAnalysis 
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                setSubmitStatus('success');

                setTimeout(() => {
                    reloadData().then(() => {
                        setActiveView('analyses');
                    });
                }, 1500);

            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }
        } catch (error) {
            console.error('Failed to submit to Google Sheets:', error);
            const errorMessage = error instanceof Error ? error.message : "An unknown error occurred.";
            setSubmitError(`Submission Failed: ${errorMessage}`);
            setSubmitStatus('error');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Registering...';
            case 'success': return 'Success!';
            case 'error': return 'Submission Failed';
            default: return 'Register Sample';
        }
    }

    return (
        <div className="space-y-8 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold text-gray-800">New Analysis Request</h1>
            <form onSubmit={handleSubmit} className="bg-white p-8 rounded-lg shadow-md space-y-6">

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                     <div>
                        <label htmlFor="folio" className="block text-sm font-medium text-gray-700">Folio</label>
                        <input type="text" name="folio" id="folio" value={formData.folio} required readOnly className={`${inputStyle} bg-gray-100 cursor-not-allowed`} />
                    </div>
                    <div>
                        <label htmlFor="receptionDate" className="block text-sm font-medium text-gray-700">Reception Date</label>
                        <input type="date" name="receptionDate" id="receptionDate" value={formData.receptionDate} onChange={handleChange} required className={inputStyle} />
                    </div>
                     <div>
                        <label htmlFor="sampleName" className="block text-sm font-medium text-gray-700">Sample Name</label>
                        <input type="text" name="sampleName" id="sampleName" value={formData.sampleName} onChange={handleChange} required className={inputStyle} />
                    </div>
                    <div>
                        <label htmlFor="product" className="block text-sm font-medium text-gray-700">Product</label>
                         <select name="product" id="product" value={formData.product} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a product</option>
                            {MOCK_PRODUCTS.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="clientId" className="block text-sm font-medium text-gray-700">Client</label>
                        <select name="clientId" id="clientId" value={formData.clientId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a client</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="technicianId" className="block text-sm font-medium text-gray-700">Assigned Technician</label>
                        <select name="technicianId" id="technicianId" value={formData.technicianId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a technician</option>
                            {technicians.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="border-t pt-6">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Select Analyses</h2>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                        {analysisCosts.map(test => (
                            <label key={test.id} className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg border border-gray-200 hover:bg-gray-100 cursor-pointer">
                                <input
                                    type="checkbox"
                                    onChange={(e) => handleTestSelection(test, e.target.checked)}
                                    checked={selectedTests.some(st => st.id === test.id)}
                                    className="h-5 w-5 rounded border-gray-300 text-primary focus:ring-secondary"
                                />
                                <span className="text-sm font-medium text-gray-700">{test.testName}</span>
                                <span className="text-sm text-gray-500">(${(typeof test.cost === 'number' ? test.cost : 0).toFixed(2)})</span>
                            </label>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 border-t pt-6">
                    <div>
                        <label htmlFor="priority" className="block text-sm font-medium text-gray-700">Priority</label>
