import React, { useState } from 'react';

const appsScriptCode = `
/**
 * LabSys - Google Apps Script Backend
 * Author: Your World-Class Senior Frontend Engineer
 * Version: 3.3 (CamelCase Key Correction)
 * Description: This script provides a generic and robust backend for the LabSys web app.
 * It handles CRUD operations for multiple sheets by using a 'targetSheet' parameter
 * in the payload, making it a scalable and centralized data management solution.
 * Now with case-insensitive header reading and correct camelCase key mapping for the frontend.
 */

// These names are now used for validation and logging, but the script is sheet-agnostic.
const EXPECTED_SHEETS = ["Clients", "Technicians", "AnalysisCosts", "AnalysisResults"];

/**
 * Handles GET requests. Fetches initial data from all relevant sheets.
 */
function doGet(e) {
  try {
    const response = {
      clients: getSheetDataAsObjects("Clients"),
      technicians: getSheetDataAsObjects("Technicians"),
      analysisCosts: getSheetDataAsObjects("AnalysisCosts"),
      analysisResults: getSheetDataAsObjects("AnalysisResults")
    };

    return ContentService.createTextOutput(JSON.stringify(response))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    Logger.log("doGet Error: " + error.stack);
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "doGet Error: " + error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Handles POST requests. Acts as a generic router for create, update, delete, and test actions.
 * Expects a 'payload' parameter containing a stringified JSON object with 'action', 'targetSheet', and 'payload'.
 */
function doPost(e) {
  try {
    if (!e || !e.parameter || !e.parameter.payload) {
      throw new Error("Invalid POST request. 'payload' parameter is missing.");
    }
    const request = JSON.parse(e.parameter.payload);
    const { action, targetSheet, payload } = request;

    if (action === 'testConnection') {
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Connection successful." }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    if (!action || !targetSheet || !payload) {
      throw new Error("Request must include 'action', 'targetSheet', and 'payload' properties.");
    }

    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(targetSheet);
    if (!sheet) {
      throw new Error("Sheet '" + targetSheet + "' not found. Please ensure the tab exists and the name is correct (case-sensitive).");
    }

    switch (action) {
      case 'delete':
        return handleDelete(payload, sheet);
      case 'create':
      case 'update':
        return handleUpsert(payload, sheet);
      default:
        throw new Error("Unknown action: '" + action + "'.");
    }

  } catch (error) {
    Logger.log("doPost Error: " + error.stack + " | Raw Payload: " + (e.parameter ? e.parameter.payload : "N/A"));
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Creates or updates a record in the given sheet. It dynamically reads headers to map data correctly.
 */
function handleUpsert(data, sheet) {
    if (sheet.getLastRow() === 0) { // If sheet is empty, it can't get headers.
      throw new Error("Cannot save to an empty sheet. Please add header columns first.");
    }
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
    const idColumnIndex = headers.indexOf('id');

    if (idColumnIndex === -1) {
      throw new Error("Target sheet must have an 'id' column.");
    }

    const rowData = headers.map(header => {
      // Find the original key in the data payload that matches the lowercase header
      const originalKey = Object.keys(data).find(k => k.toLowerCase() === header);
      const value = originalKey ? data[originalKey] : undefined;

      if (Array.isArray(value)) {
        return value.join(','); // Store array as comma-separated string
      }
      return value !== undefined && value !== null ? value : "";
    });

    const sheetData = sheet.getDataRange().getValues();
    let recordUpdated = false;

    // Start from 1 to skip header row
    for (let i = 1; i < sheetData.length; i++) {
      if (sheetData[i][idColumnIndex] == data.id) {
        sheet.getRange(i + 1, 1, 1, headers.length).setValues([rowData]);
        recordUpdated = true;
        break;
      }
    }

    if (!recordUpdated) {
      sheet.appendRow(rowData);
    }

    const message = recordUpdated ? "Data updated successfully in " + sheet.getName() : "Data added successfully to " + sheet.getName();
    return ContentService.createTextOutput(JSON.stringify({ status: "success", message: message }))
      .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Deletes a record from the given sheet based on its ID.
 */
function handleDelete(data, sheet) {
  if (!data.id) {
    throw new Error("Delete action requires an 'id' in the payload.");
  }

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
  const idColumnIndex = headers.indexOf('id');

  if (idColumnIndex === -1) {
    throw new Error("Cannot delete: target sheet must have an 'id' column.");
  }

  const sheetData = sheet.getDataRange().getValues();
  for (let i = sheetData.length - 1; i >= 1; i--) {
    if (sheetData[i][idColumnIndex] == data.id) {
      sheet.deleteRow(i + 1);
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row deleted successfully from " + sheet.getName() }))
        .setMimeType(ContentService.MimeType.JSON);
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row already deleted or not found." }))
    .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Helper to get all data from a sheet and convert to an array of objects with camelCase keys.
 */
function getSheetDataAsObjects(sheetName) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet || sheet.getLastRow() < 2) return []; // Return empty if no data rows

  const dataRange = sheet.getDataRange();
  const data = dataRange.getValues();

  // Normalize headers: lowercase and trim whitespace for robustness
  const headers = data.shift().map(header => String(header).toLowerCase().trim()); 

  const numericHeaders = ['cost', 'protein', 'fat', 'moisture', 'ash', 'fiber', 'starch'];

  // This map ensures that keys sent to the frontend are in the correct camelCase format
  // that the React components expect, solving inconsistencies from case-insensitive reading.
  const headerMap = {
    'contactperson': 'contactPerson',
    'hiredate': 'hireDate',
    'testname': 'testName',
    'receptiondate': 'receptionDate',
    'deliverydate': 'deliveryDate',
    'samplename': 'sampleName',
    'clientid': 'clientId',
    'technicianid': 'technicianId',
    'requestedtests': 'requestedTests'
  };

  return data.map(row => {
    const obj = {};
    headers.forEach((header, index) => {
      let value = row[index];
      if (numericHeaders.includes(header) && !isNaN(value) && value !== '') {
        value = Number(value);
      } else if (header === 'requestedtests' && typeof value === 'string') {
        // Split and trim each item to prevent issues with whitespace
        value = value ? value.split(',').map(item => item.trim()) : [];
      }
      // Use the map to get the correct camelCase key for the frontend object
      const key = headerMap[header] || header;
      obj[key] = value;
    });
    return obj;
  });
}
`.trim();

const CodeBlock: React.FC = () => {
