            .map(testName => {
                const mapping = getTestMapping(testName);
                if (!mapping) return null;
                const result = analysis[mapping.propName];
                const displayName = mapping.canonicalName.split('(')[0].trim();
                return [displayName, mapping.method ?? 'N/A', typeof result === 'number' ? result.toFixed(2) + ' %' : 'N/A'];
            })
            .filter((row): row is [string, string, string] => row !== null);

        autoTable(doc, {
            startY: 85,
