import Table from './ui/Table';
import Modal from './ui/Modal';
import { DownloadIcon, SheetIcon, PlusIcon } from './icons/Icons';

const testNameToPropertyMap: { [key: string]: keyof Analysis } = {
    'Protein': 'protein',
    'Fat': 'fat',
    'Moisture': 'moisture',
    'Fiber': 'fiber',
    'Ash': 'ash',
    'Starch': 'starch',
};

/**
 * Intelligently maps a user-defined test name from the sheet to the system's canonical test data.
 * It works by checking if the sheet test name contains the base name of a canonical test (e.g., "Protein"), ignoring case.
 * @param testNameFromSheet The test name as it appears in the Google Sheet.
 * @returns An object with the canonical name and property name, or null if no match is found.
 */
const getTestMapping = (testNameFromSheet: string): { canonicalName: string; propName: keyof Analysis } | null => {
    const lowerCaseTestName = testNameFromSheet.toLowerCase();

    const canonicalName = Object.keys(testNameToPropertyMap).find(key => {
        const baseName = key.split('(')[0].trim().toLowerCase();
        return lowerCaseTestName.includes(baseName);
    });

    if (canonicalName) {
        return {
            canonicalName,
            propName: testNameToPropertyMap[canonicalName],
        };
    }

    return null;
};


const statusOptions: AnalysisStatus[] = ['Received', 'In Progress', 'Completed', 'Cancelled'];

interface AnalysisManagementProps {
    analyses: Analysis[];
    clients: Client[];
    technicians: Technician[];
    analysisCosts: AnalysisCost[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ analyses, clients, technicians, analysisCosts, reloadData, setActiveView }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);
    const [modalFormData, setModalFormData] = useState<Partial<Analysis>>({});
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

    const handleEdit = (index: number) => {
        const analysisToEdit = analyses[index];
        setEditingAnalysis(analysisToEdit);
        setModalFormData(analysisToEdit);
        setIsModalOpen(true);
    };

    const handleDelete = async (index: number) => {
        if (window.confirm('Are you sure you want to delete this analysis? This will also remove it from your Google Sheet.')) {
            const analysisToDelete = analyses[index];
            const googleScriptUrl = localStorage.getItem('googleScriptUrl');

            if (!googleScriptUrl) {
                alert('Google Sheets URL not configured. Please set it in Settings.');
                return;
            }

            try {
                const requestPayload = {
                    action: 'delete',
                    targetSheet: 'AnalysisResults',
                    payload: { id: analysisToDelete.id }
                };
                const postData = new URLSearchParams();
                postData.append('payload', JSON.stringify(requestPayload));

                const response = await fetch(googleScriptUrl, {
                    method: 'POST',
                    body: postData,
                });
                const result = await response.json();

                if (result.status === 'success') {
                    await reloadData();
                    alert('Analysis deleted successfully.');
                } else {
                    throw new Error(result.message || 'Unknown error from Google Script.');
                }
            } catch (error) {
                console.error('Failed to delete from Google Sheets:', error);
                alert(`Failed to delete analysis. Error: ${error instanceof Error ? error.message : String(error)}`);
            }
        }
