import React, { useState, useEffect } from 'react';
import CodeBlock from './ui/CodeBlock';

interface SettingsProps {
    reloadData: () => Promise<void>;
}

const Settings: React.FC<SettingsProps> = ({ reloadData }) => {
    const [googleScriptUrl, setGoogleScriptUrl] = useState('');
    const [testStatus, setTestStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');

    useEffect(() => {
        const savedUrl = localStorage.getItem('googleScriptUrl');
        if (savedUrl) {
            setGoogleScriptUrl(savedUrl);
        }
    }, []);

    const handleSaveUrl = () => {
        localStorage.setItem('googleScriptUrl', googleScriptUrl);
        alert('URL saved successfully! Please refresh the page to load data.');
    };

    const handleTestConnection = async () => {
        if (!googleScriptUrl) {
            alert('Please enter a URL first.');
            return;
        }
        setTestStatus('testing');
        try {
            // Test 1: GET request
            const getResponse = await fetch(googleScriptUrl);
            if (!getResponse.ok) throw new Error(`GET Test Failed: Status ${getResponse.status}`);
            const getResult = await getResponse.json();
            if (!getResult || typeof getResult !== 'object' || !getResult.clients || !getResult.analysisTypes) throw new Error(`GET Test Failed: Invalid JSON response. Missing required data like clients or analysisTypes.`);

            // Test 2: POST request using URLSearchParams to avoid CORS preflight
            const postData = new URLSearchParams();
            const requestPayload = { action: 'testConnection', targetSheet: 'any', payload: {} };
            postData.append('payload', JSON.stringify(requestPayload));

            const postResponse = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData
            });
            if (!postResponse.ok) throw new Error(`POST Test Failed: Status ${postResponse.status}`);
            const postResult = await postResponse.json();
            if (postResult.status !== 'success') throw new Error(`POST Test Failed: ${postResult.message}`);

            setTestStatus('success');
        } catch (error) {
            console.error('Connection test failed:', error);
            setTestStatus('error');
        } finally {
            setTimeout(() => setTestStatus('idle'), 5000);
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    return (
        <div className="space-y-8">
            <h1 className="text-3xl font-bold text-gray-800">Settings</h1>

            <div className="space-y-8">
                <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Google Sheets Integration</h2>
                     <p className="text-gray-600 mt-2 mb-4">
                        Connect your Google Sheet as a database. This allows the app to load your clients, technicians, and costs, and also to submit new analysis results.
                     </p>
                    <div>
                        <label htmlFor="googleScriptUrl" className="block text-sm font-medium text-gray-700">Apps Script URL</label>
                        <input 
                            type="url" 
                            name="googleScriptUrl" 
                            id="googleScriptUrl" 
                            value={googleScriptUrl}
                            onChange={(e) => setGoogleScriptUrl(e.target.value)}
                            className={inputStyle}
                            placeholder="https://script.google.com/macros/s/..."
                        />
                    </div>
                    <div className="flex items-center space-x-2 mt-4">
                        <button onClick={handleSaveUrl} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg transition-colors">
                           Save URL
                        </button>
                        <button onClick={handleTestConnection} className="bg-gray-600 text-white hover:bg-gray-700 font-bold py-2 px-4 rounded-lg transition-colors" disabled={testStatus === 'testing'}>
                           {testStatus === 'testing' ? 'Testing...' : 'Test Connection'}
                        </button>
                        {testStatus === 'success' && <span className="text-green-600 font-medium">Connection successful!</span>}
                        {testStatus === 'error' && <span className="text-red-600 font-medium">Connection failed. Check URL/permissions and browser console for CORS errors.</span>}
                    </div>
                </div>

                 <div className="bg-white p-6 rounded-lg shadow-md">
                     <h2 className="text-2xl font-semibold text-gray-700">Setup Your Google Sheet as a Database</h2>
                     <div className="prose max-w-none mt-4 text-gray-800">
                        <p>Follow these steps to get your Google Sheet ready:</p>
                        <ol className="list-decimal pl-5 space-y-2">
                            <li>Create a new Google Sheet.</li>
                            <li>Create five tabs named exactly: <strong>Clients</strong>, <strong>Technicians</strong>, <strong>AnalysisTypes</strong>, <strong>AnalysisCosts</strong>, and <strong>AnalysisResults</strong>.</li>
                            <li>In the first row of each sheet, add the required headers.
                                <ul className="list-disc pl-5 mt-1 space-y-1">
                                    <li><strong>Clients:</strong> id, name, contactPerson, email, phone</li>
                                    <li><strong>Technicians:</strong> id, name, specialty, hireDate</li>
                                    <li><strong>AnalysisTypes:</strong> id, testName, units, resultType (use 'numeric' or 'text')</li>
                                    <li><strong>AnalysisCosts:</strong> id, testName, cost, method</li>
                                    <li><strong>AnalysisResults:</strong> id, folio, receptionDate, deliveryDate, sampleName, product, subtype, clientId, technicianId, priority, status, cost, requestedTests, results</li>
                                </ul>
                            </li>
                            <li>Go to `Extensions &gt; Apps Script`, paste the code below, and save the project.</li>
                            <li>Click `Deploy &gt; New Deployment`. Select `Web app` as the type.</li>
                            <li>In the dialog, set `Execute as` to `Me` and `Who has access` to `Anyone`.</li>
                            <li>Click `Deploy`. Authorize the script's permissions when prompted.</li>
                            <li>Copy the `Web app URL` provided and paste it into the input field above.</li>
                        </ol>
                        <div className="mt-4 p-4 bg-yellow-100 border-l-4 border-yellow-500 text-yellow-800 rounded-r-lg">
                            <h4 className="font-bold">Troubleshooting Connection Errors</h4>
                            <p>The most common error is a "CORS" or "Network" error. This happens because Google Scripts can block certain types of web requests. The code provided here is specifically designed to avoid this issue. If you still see an error like "Sheet not found", it means the name of the tab in your Google Sheet does not <strong className="font-extrabold">exactly</strong> match the name required (e.g., "AnalysisResults"). Names are case-sensitive. After any script change, you must re-deploy: select <strong>Deploy &gt; Manage Deployments</strong>, edit your deployment, choose a <strong>New version</strong>, and click <strong>Deploy</strong>.</p>
                        </div>
                     </div>
                     <CodeBlock />
                </div>
            </div>
        </div>
    );
};

export default Settings;

import React, { useState } from 'react';

const appsScriptCode = `
/**
 * LabSys - Google Apps Script Backend
 * Author: Your World-Class Senior Frontend Engineer
 * Version: 4.0 (Dynamic Analysis & Results)
 * Description: This script provides a generic and robust backend for the LabSys web app.
 * It now supports a dynamic list of analysis types managed from a dedicated "AnalysisTypes" sheet
 * and stores analysis results in a flexible JSON format within a single "results" column.
 */

// These names are now used for validation and logging, but the script is sheet-agnostic.
const EXPECTED_SHEETS = ["Clients", "Technicians", "AnalysisCosts", "AnalysisResults", "AnalysisTypes"];

/**
 * Handles GET requests. Fetches initial data from all relevant sheets.
 */
function doGet(e) {
  try {
    const response = {
      clients: getSheetDataAsObjects("Clients"),
      technicians: getSheetDataAsObjects("Technicians"),
      analysisTypes: getSheetDataAsObjects("AnalysisTypes"),
      analysisCosts: getSheetDataAsObjects("AnalysisCosts"),
      analysisResults: getSheetDataAsObjects("AnalysisResults")
    };

    return ContentService.createTextOutput(JSON.stringify(response))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    Logger.log("doGet Error: " + error.stack);
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "doGet Error: " + error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Handles POST requests. Acts as a generic router for create, update, delete, and test actions.
 * Expects a 'payload' parameter containing a stringified JSON object with 'action', 'targetSheet', and 'payload'.
 */
function doPost(e) {
  try {
    if (!e || !e.parameter || !e.parameter.payload) {
      throw new Error("Invalid POST request. 'payload' parameter is missing.");
    }
    const request = JSON.parse(e.parameter.payload);
    const { action, targetSheet, payload } = request;

    if (action === 'testConnection') {
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Connection successful." }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    if (!action || !targetSheet || !payload) {
      throw new Error("Request must include 'action', 'targetSheet', and 'payload' properties.");
    }

    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(targetSheet);
    if (!sheet) {
      throw new Error("Sheet '" + targetSheet + "' not found. Please ensure the tab exists and the name is correct (case-sensitive).");
    }

    switch (action) {
      case 'delete':
        return handleDelete(payload, sheet);
      case 'create':
      case 'update':
        return handleUpsert(payload, sheet);
      default:
        throw new Error("Unknown action: '" + action + "'.");
    }

  } catch (error) {
    Logger.log("doPost Error: " + error.stack + " | Raw Payload: " + (e.parameter ? e.parameter.payload : "N/A"));
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Creates or updates a record in the given sheet. It dynamically reads headers to map data correctly.
 */
function handleUpsert(data, sheet) {
    if (sheet.getLastRow() === 0) { // If sheet is empty, it can't get headers.
      throw new Error("Cannot save to an empty sheet. Please add header columns first.");
    }
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
    const idColumnIndex = headers.indexOf('id');

    if (idColumnIndex === -1) {
      throw new Error("Target sheet must have an 'id' column.");
    }

    const rowData = headers.map(header => {
      // Find the original key in the data payload that matches the lowercase header
      const originalKey = Object.keys(data).find(k => k.toLowerCase() === header);
      const value = originalKey ? data[originalKey] : undefined;

      // Handle special data structures before saving to sheet
      if (Array.isArray(value)) {
        if (header === 'results') {
           return JSON.stringify(value); // Store results array as a JSON string
        }
        return value.join(','); // Store other arrays as comma-separated string
      }
      return value !== undefined && value !== null ? value : "";
    });

    const sheetData = sheet.getDataRange().getValues();
    let recordUpdated = false;

    // Start from 1 to skip header row
    for (let i = 1; i < sheetData.length; i++) {
      if (sheetData[i][idColumnIndex] == data.id) {
        sheet.getRange(i + 1, 1, 1, headers.length).setValues([rowData]);
        recordUpdated = true;
        break;
      }
    }

    if (!recordUpdated) {
      sheet.appendRow(rowData);
    }

    const message = recordUpdated ? "Data updated successfully in " + sheet.getName() : "Data added successfully to " + sheet.getName();
    return ContentService.createTextOutput(JSON.stringify({ status: "success", message: message }))
      .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Deletes a record from the given sheet based on its ID.
 */
function handleDelete(data, sheet) {
  if (!data.id) {
    throw new Error("Delete action requires an 'id' in the payload.");
  }

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
  const idColumnIndex = headers.indexOf('id');

  if (idColumnIndex === -1) {
    throw new Error("Cannot delete: target sheet must have an 'id' column.");
  }

  const sheetData = sheet.getDataRange().getValues();
  for (let i = sheetData.length - 1; i >= 1; i--) {
    if (sheetData[i][idColumnIndex] == data.id) {
      sheet.deleteRow(i + 1);
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row deleted successfully from " + sheet.getName() }))
        .setMimeType(ContentService.MimeType.JSON);
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row already deleted or not found." }))
    .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Helper to get all data from a sheet and convert to an array of objects with camelCase keys.
 */
function getSheetDataAsObjects(sheetName) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet || sheet.getLastRow() < 2) return []; // Return empty if no data rows

  const dataRange = sheet.getDataRange();
  const data = dataRange.getValues();

  // Normalize headers: lowercase and trim whitespace for robustness
  const headers = data.shift().map(header => String(header).toLowerCase().trim()); 

  const numericHeaders = ['cost'];

  // This map ensures that keys sent to the frontend are in the correct camelCase format
  // that the React components expect, solving inconsistencies from case-insensitive reading.
  const headerMap = {
    'contactperson': 'contactPerson',
    'hiredate': 'hireDate',
    'testname': 'testName',
    'resulttype': 'resultType',
    'receptiondate': 'receptionDate',
    'deliverydate': 'deliveryDate',
    'samplename': 'sampleName',
    'clientid': 'clientId',
    'technicianid': 'technicianId',
    'requestedtests': 'requestedTests'
  };

  return data.map(row => {
    const obj = {};
    headers.forEach((header, index) => {
      let value = row[index];
      if (numericHeaders.includes(header) && !isNaN(value) && value !== '') {
        value = Number(value);
      } else if (header === 'requestedtests' && typeof value === 'string') {
        value = value ? value.split(',').map(item => item.trim()) : [];
      } else if (header === 'results' && typeof value === 'string') {
        try {
          value = value ? JSON.parse(value) : [];
        } catch (e) {
          Logger.log("Could not parse results JSON for row: " + value);
          value = []; // Default to empty array on parsing error
        }
      }

      const key = headerMap[header] || header;
      obj[key] = value;
    });
    return obj;
  });
}
`.trim();

const CodeBlock: React.FC = () => {
    const [copyStatus, setCopyStatus] = useState('Copy');

