import React, { useState } from 'react';
import { AnalysisCost, AnalysisType } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { PlusIcon } from './icons/Icons';

const initialCostFormState: Omit<AnalysisCost, 'id'> = {
    testName: '',
    cost: 0,
    method: ''
};

interface AnalysisCostsManagementProps {
    analysisCosts: AnalysisCost[];
    analysisTypes: AnalysisType[];
    reloadData: () => Promise<void>;
}

const AnalysisCostsManagement: React.FC<AnalysisCostsManagementProps> = ({ analysisCosts, analysisTypes, reloadData }) => {
    const [isCostModalOpen, setIsCostModalOpen] = useState(false);
    const [costFormData, setCostFormData] = useState(initialCostFormState);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
    const [submitError, setSubmitError] = useState<string | null>(null);

    const handleCloseCostModal = () => {
        setIsCostModalOpen(false);
        setCostFormData(initialCostFormState);
        setSubmitStatus('idle');
        setSubmitError(null);
    };

    const handleCostFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        setCostFormData(prev => ({
            ...prev,
            [name]: type === 'number' ? parseFloat(value) : value
        }));
    };

    const handleCostFormSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (!costFormData.testName || !costFormData.method || costFormData.cost <= 0) {
            alert('Please fill all fields correctly. Cost must be greater than 0.');
            return;
        }

        setSubmitStatus('submitting');
        setSubmitError(null);

        const newCost: AnalysisCost = {
            id: `c${Date.now()}`,
            ...costFormData
        };

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            setSubmitError('Google Sheets URL not configured.');
            setSubmitStatus('error');
            return;
        }

        try {
            const requestPayload = { 
                action: 'create', 
                targetSheet: 'AnalysisCosts', 
                payload: newCost
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                await reloadData();
                setSubmitStatus('success');
                setTimeout(() => handleCloseCostModal(), 1000);
            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }

        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : "An unknown error occurred.";
            setSubmitError(`Failed to save cost: ${errorMessage}.`);
            setSubmitStatus('error');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Saving...';
            case 'success': return 'Saved!';
            case 'error': return 'Retry Save';
            default: return 'Save Cost';
        }
    }

    // Get analysis types that don't already have a cost assigned.
    const availableAnalysisTypes = analysisTypes.filter(
        at => !analysisCosts.some(ac => ac.testName === at.testName)
    );

    const headers = ['Test Name', 'Method', 'Cost ($)'];
    const dataRows = analysisCosts.map(c => [c.testName, c.method, (typeof c.cost === 'number' ? c.cost : 0).toFixed(2)]);

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold text-gray-800">Analysis Costs Management</h1>
                 <button onClick={() => setIsCostModalOpen(true)} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                    <PlusIcon /> <span className="ml-2">Add Cost</span>
                </button>
            </div>
            <Table headers={headers} data={dataRows} />

            {isCostModalOpen && (
                <Modal onClose={handleCloseCostModal} title="Add New Analysis Cost">
                    <form onSubmit={handleCostFormSubmit}>
                        <div className="p-6 space-y-4">
                            <div>
                                <label htmlFor="testName" className="block text-sm font-medium text-gray-700">Test Name</label>
                                <select 
                                    name="testName" 
                                    id="testName" 
                                    value={costFormData.testName} 
                                    onChange={handleCostFormChange} 
                                    required 
                                    className={inputStyle}
                                >
                                    <option value="" disabled>Select an analysis</option>
                                    {availableAnalysisTypes.map(type => <option key={type.id} value={type.testName}>{type.testName}</option>)}
                                </select>
                                <p className="mt-2 text-xs text-gray-500">
                                    This list is managed from your 'AnalysisTypes' sheet. You can only add costs for analyses that are not already in the table above.
                                </p>
                            </div>
                            <div>
                                <label htmlFor="method" className="block text-sm font-medium text-gray-700">Analytical Method</label>
                                <input type="text" name="method" id="method" value={costFormData.method} onChange={handleCostFormChange} required className={inputStyle} placeholder="e.g., AOAC 984.13"/>
                            </div>
                            <div>
                                <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Cost ($)</label>
                                <input type="number" name="cost" id="cost" value={costFormData.cost} onChange={handleCostFormChange} required className={inputStyle} step="0.01" min="0"/>
                            </div>
                             {submitStatus === 'error' && submitError && (
                                <div className="text-xs text-center p-2 bg-red-50 text-red-700 rounded-md">{submitError}</div>
                            )}
                        </div>
                        <div className="flex justify-end p-4 bg-gray-50 border-t">
                             <button type="button" onClick={handleCloseCostModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                                Cancel
                            </button>
                            <button type="submit" className={`font-bold py-2 px-4 rounded-lg transition-colors text-white ${
                                submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' :
                                submitStatus === 'success' ? 'bg-green-600' :
                                submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                                'bg-primary hover:bg-secondary'
                            }`} disabled={submitStatus === 'submitting' || submitStatus === 'success'}>
                                {getButtonText()}
                            </button>
                        </div>
                    </form>
                </Modal>
            )}
        </div>
    );
};

export default AnalysisCostsManagement;

import React, { useState, useEffect } from 'react';
import { Analysis, Client, Technician, AnalysisPriority, AnalysisCost, View } from '../types';

const MOCK_PRODUCTS: string[] = [ 'Corn', 'Soybean Meal', 'Wheat Midds', 'Fishmeal', 'DDGS' ];
const priorityOptions: AnalysisPriority[] = ['Normal', 'Urgent', 'Low'];

interface AnalysisRequestProps {
    clients: Client[];
    technicians: Technician[];
    analysisCosts: AnalysisCost[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

let folioCounter = new Date().getMilliseconds();

const generateFolio = (): string => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const sequence = String(folioCounter++).padStart(4, '0');
    return `${year}${month}${sequence}`;
};

const initialFormData = {
    folio: '',
    receptionDate: new Date().toISOString().split('T')[0],
    sampleName: '',
    product: '',
    subtype: '',
    clientId: '',
    technicianId: '',
    priority: 'Normal' as AnalysisPriority,
};

const AnalysisRequest: React.FC<AnalysisRequestProps> = ({ reloadData, setActiveView, analysisCosts, clients, technicians }) => {
    const [formData, setFormData] = useState(initialFormData);
    const [selectedTests, setSelectedTests] = useState<AnalysisCost[]>([]);
    const [totalCost, setTotalCost] = useState(0);
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
    const [submitError, setSubmitError] = useState<string | null>(null);

    useEffect(() => {
        setFormData(prev => ({ ...prev, folio: generateFolio() }));
    }, []);

    useEffect(() => {
        const newCost = selectedTests.reduce((sum, test) => sum + (Number(test.cost) || 0), 0);
        setTotalCost(newCost);
    }, [selectedTests]);

    const handleTestSelection = (test: AnalysisCost, isChecked: boolean) => {
        if (isChecked) {
            setSelectedTests(prev => [...prev, test]);
        } else {
            setSelectedTests(prev => prev.filter(t => t.id !== test.id));
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
         if (selectedTests.length === 0 || !formData.clientId || !formData.technicianId) {
            alert("Please select a client, technician, and at least one test.");
            return;
        }
        setSubmitStatus('submitting');
        setSubmitError(null);

        const newAnalysis: Analysis = {
            ...formData,
            id: `an${Date.now()}`,
            cost: totalCost,
            requestedTests: selectedTests.map(t => t.testName),
            status: 'Received',
            results: selectedTests.map(t => ({ testName: t.testName, value: null })), // Initialize results array
        };

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            setSubmitError('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        try {
            const requestPayload = { 
                action: 'create', 
                targetSheet: 'AnalysisResults', 
                payload: newAnalysis 
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                setSubmitStatus('success');

                setTimeout(() => {
                    reloadData().then(() => {
                        setActiveView('analyses');
                    });
                }, 1500);

            } else {
                throw new Error(result.message || 'Unknown error from Google Script.');
            }
        } catch (error) {
            console.error('Failed to submit to Google Sheets:', error);
            const errorMessage = error instanceof Error ? error.message : "An unknown error occurred.";
            setSubmitError(`Submission Failed: ${errorMessage}`);
            setSubmitStatus('error');
        }
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    const getButtonText = () => {
        switch(submitStatus) {
            case 'submitting': return 'Registering...';
            case 'success': return 'Success!';
            case 'error': return 'Submission Failed';
            default: return 'Register Sample';
        }
    }

    return (
        <div className="space-y-8 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold text-gray-800">New Analysis Request</h1>
            <form onSubmit={handleSubmit} className="bg-white p-8 rounded-lg shadow-md space-y-6">

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                     <div>
                        <label htmlFor="folio" className="block text-sm font-medium text-gray-700">Folio</label>
                        <input type="text" name="folio" id="folio" value={formData.folio} required readOnly className={`${inputStyle} bg-gray-100 cursor-not-allowed`} />
                    </div>
                    <div>
                        <label htmlFor="receptionDate" className="block text-sm font-medium text-gray-700">Reception Date</label>
                        <input type="date" name="receptionDate" id="receptionDate" value={formData.receptionDate} onChange={handleChange} required className={inputStyle} />
                    </div>
                     <div>
                        <label htmlFor="sampleName" className="block text-sm font-medium text-gray-700">Sample Name</label>
                        <input type="text" name="sampleName" id="sampleName" value={formData.sampleName} onChange={handleChange} required className={inputStyle} />
                    </div>
                    <div>
                        <label htmlFor="product" className="block text-sm font-medium text-gray-700">Product</label>
                         <select name="product" id="product" value={formData.product} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a product</option>
                            {MOCK_PRODUCTS.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="clientId" className="block text-sm font-medium text-gray-700">Client</label>
                        <select name="clientId" id="clientId" value={formData.clientId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a client</option>
                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="technicianId" className="block text-sm font-medium text-gray-700">Assigned Technician</label>
                        <select name="technicianId" id="technicianId" value={formData.technicianId} onChange={handleChange} required className={inputStyle}>
                            <option value="" disabled>Select a technician</option>
                            {technicians.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>
                </div>

                <div className="border-t pt-6">
                    <h2 className="text-xl font-semibold text-gray-700 mb-4">Select Analyses</h2>
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                        {analysisCosts.map(test => (
                            <label key={test.id} className="flex items-center space-x-3 p-3 bg-gray-50 rounded-lg border border-gray-200 hover:bg-gray-100 cursor-pointer">
                                <input
                                    type="checkbox"
                                    onChange={(e) => handleTestSelection(test, e.target.checked)}
                                    checked={selectedTests.some(st => st.id === test.id)}
                                    className="h-5 w-5 rounded border-gray-300 text-primary focus:ring-secondary"
                                />
                                <span className="text-sm font-medium text-gray-700">{test.testName}</span>
                                <span className="text-sm text-gray-500">(${(typeof test.cost === 'number' ? test.cost : 0).toFixed(2)})</span>
                            </label>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 border-t pt-6">
                    <div>
                        <label htmlFor="priority" className="block text-sm font-medium text-gray-700">Priority</label>
                        <select name="priority" id="priority" value={formData.priority} onChange={handleChange} required className={inputStyle}>
                            {priorityOptions.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="cost" className="block text-sm font-medium text-gray-700">Total Cost ($)</label>
                        <input type="text" name="cost" id="cost" value={totalCost.toFixed(2)} readOnly className={`${inputStyle} bg-gray-100 cursor-not-allowed`} />
                    </div>
                </div>

                <div className="flex justify-end pt-4 flex-col items-end">
                    <button 
                        type="submit" 
                        className={`font-bold py-2 px-6 rounded-lg inline-flex items-center transition-colors w-auto ${
                            submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' : 
                            submitStatus === 'success' ? 'bg-green-600' :
                            submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                            'bg-primary hover:bg-secondary'
                        } text-white`}
                        disabled={submitStatus === 'submitting' || submitStatus === 'success' || selectedTests.length === 0 || !formData.clientId || !formData.technicianId}
                    >
                        {getButtonText()}
                    </button>
                    {submitStatus === 'error' && submitError && (
                        <div className="mt-4 text-center p-4 bg-red-50 border border-red-200 rounded-lg w-full">
                            <p className="text-sm font-bold text-red-700">{submitError}</p>
                            <p className="mt-2 text-xs text-gray-600">Please check your Apps Script URL in Settings. Ensure your Google Sheet file has a tab named exactly <strong className="font-extrabold">AnalysisResults</strong>. Names are case-sensitive.</p>
                        </div>
                    )}
                </div>
            </form>
        </div>
    );
};

export default AnalysisRequest;

import React, { useState } from 'react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Analysis, Client, Technician, View, AnalysisStatus, AnalysisCost, AnalysisType, AnalysisResultItem } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { DownloadIcon, SheetIcon, PlusIcon } from './icons/Icons';

const statusOptions: AnalysisStatus[] = ['Received', 'In Progress', 'Completed', 'Cancelled'];

interface AnalysisManagementProps {
    analyses: Analysis[];
    clients: Client[];
    technicians: Technician[];
    analysisCosts: AnalysisCost[];
    analysisTypes: AnalysisType[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ analyses, clients, technicians, analysisCosts, analysisTypes, reloadData, setActiveView }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);
    const [modalFormData, setModalFormData] = useState<Partial<Analysis>>({});
    const [submitStatus, setSubmitStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

    const handleEdit = (index: number) => {
        const analysisToEdit = analyses[index];
        setEditingAnalysis(analysisToEdit);
        // Ensure results array exists and has entries for all requested tests
        const initialResults = analysisToEdit.requestedTests.map(testName => {
            const existingResult = (analysisToEdit.results || []).find(r => r.testName === testName);
            return existingResult || { testName, value: null };
        });
        setModalFormData({ ...analysisToEdit, results: initialResults });
        setIsModalOpen(true);
    };

    const handleDelete = async (index: number) => {
        if (window.confirm('Are you sure you want to delete this analysis? This will also remove it from your Google Sheet.')) {
            const analysisToDelete = analyses[index];
            const googleScriptUrl = localStorage.getItem('googleScriptUrl');

            if (!googleScriptUrl) {
                alert('Google Sheets URL not configured. Please set it in Settings.');
                return;
            }

            try {
                const requestPayload = {
                    action: 'delete',
                    targetSheet: 'AnalysisResults',
                    payload: { id: analysisToDelete.id }
                };
                const postData = new URLSearchParams();
                postData.append('payload', JSON.stringify(requestPayload));

                const response = await fetch(googleScriptUrl, {
                    method: 'POST',
                    body: postData,
                });
                const result = await response.json();

                if (result.status === 'success') {
                    await reloadData();
                    alert('Analysis deleted successfully.');
                } else {
                    throw new Error(result.message || 'Unknown error from Google Script.');
                }
            } catch (error) {
                console.error('Failed to delete from Google Sheets:', error);
                alert(`Failed to delete analysis. Error: ${error instanceof Error ? error.message : String(error)}`);
            }
        }
    };

    const handlePrint = (index: number) => {
        handlePrintReport(analyses[index]);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingAnalysis(null);
        setSubmitStatus('idle');
    };

    const handleModalFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setModalFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleModalResultChange = (testName: string, value: string) => {
        setModalFormData(prev => {
            const newResults = [...(prev.results || [])];
            const resultIndex = newResults.findIndex(r => r.testName === testName);
            const analysisType = analysisTypes.find(at => at.testName === testName);

            let finalValue: string | number | null = value;
            if (analysisType?.resultType === 'numeric') {
                if (value === '') {
                    finalValue = null; // Store null if the field is empty
                } else {
                    const parsedValue = parseFloat(value);
                    // Store null if parsing results in NaN, otherwise store the number
                    finalValue = isNaN(parsedValue) ? null : parsedValue;
                }
            }

            if (resultIndex > -1) {
                newResults[resultIndex] = { ...newResults[resultIndex], value: finalValue };
            } else {
                newResults.push({ testName, value: finalValue });
            }
            return { ...prev, results: newResults };
        });
    }

    const handleSaveAndSubmit = async () => {
        if (!editingAnalysis || !modalFormData) return;

        setSubmitStatus('submitting');

        const googleScriptUrl = localStorage.getItem('googleScriptUrl');
        if (!googleScriptUrl) {
            alert('Google Sheets URL not configured. Please set it in Settings.');
            setSubmitStatus('error');
            return;
        }

        const updatedAnalysisData: Analysis = {
            ...editingAnalysis,
            ...modalFormData,
            // Ensure results are properly structured
            results: modalFormData.results || editingAnalysis.results,
        };

        try {
            const requestPayload = {
                action: 'update',
                targetSheet: 'AnalysisResults',
                payload: updatedAnalysisData
            };
            const postData = new URLSearchParams();
            postData.append('payload', JSON.stringify(requestPayload));

            const response = await fetch(googleScriptUrl, {
                method: 'POST',
                body: postData,
            });
            const result = await response.json();

            if (result.status === 'success') {
                setSubmitStatus('success');
                setTimeout(async () => {
                    await reloadData();
                    handleCloseModal();
                }, 1500);
            } else {
                 throw new Error(result.message || 'Unknown error from Google Script.');
            }
        } catch (error) {
             console.error('Failed to submit to Google Sheets:', error);
             alert(`Failed to submit data. Error: ${error instanceof Error ? error.message : String(error)}`);
             setSubmitStatus('error');
        }
    }

    const headers = ['Folio', 'Reception', 'Delivery', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status'];
    const dataRows = analyses.map(a => [
        a.folio, 
        a.receptionDate,
        a.deliveryDate ?? 'N/A',
        a.sampleName,
        a.product,
        clients.find(c => c.id === a.clientId)?.name ?? 'Unknown',
        technicians.find(t => t.id === a.technicianId)?.name ?? 'Unknown',
        a.priority,
        a.status,
    ]);

    const handleDownloadPdf = () => {
        const doc = new jsPDF();
        doc.text("Analysis Report", 14, 15);
        autoTable(doc, {
            head: [headers],
            body: dataRows,
            startY: 20,
            theme: 'grid',
            headStyles: { fillColor: [30, 64, 175] },
        });
        doc.save('analysis-report.pdf');
    };

    const handleExportCSV = () => {
        const allTestNames = [...new Set(analyses.flatMap(a => a.requestedTests))];
        const csvHeaders = ['Folio', 'Reception Date', 'Delivery Date', 'Sample', 'Product', 'Client', 'Technician', 'Priority', 'Status', 'Cost ($)', ...allTestNames];

        const escapeCsvCell = (cell: any): string => {
            const strCell = String(cell ?? '');
            if (strCell.includes(',') || strCell.includes('"') || strCell.includes('\n')) {
                return `"${strCell.replace(/"/g, '""')}"`;
            }
            return strCell;
        };

        const csvRows = analyses.map(a => {
            const clientName = clients.find(c => c.id === a.clientId)?.name ?? 'Unknown';
            const technicianName = technicians.find(t => t.id === a.technicianId)?.name ?? 'Unknown';
            const resultsMap = new Map((a.results || []).map(r => [r.testName, r.value]));

            const resultValues = allTestNames.map(testName => resultsMap.get(testName) ?? '');

            return [
                a.folio, a.receptionDate, a.deliveryDate, a.sampleName, a.product,
                clientName, technicianName, a.priority, a.status, a.cost,
                ...resultValues
            ].map(escapeCsvCell).join(',');
        });

        const csvContent = [csvHeaders.join(','), ...csvRows].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", "analysis-report.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handlePrintReport = (analysis: Analysis) => {
        const doc = new jsPDF();
        const client = clients.find(c => c.id === analysis.clientId);
        const technician = technicians.find(t => t.id === analysis.technicianId);
        const pageHeight = doc.internal.pageSize.getHeight();
        const pageWidth = doc.internal.pageSize.getWidth();
        const margin = 14;

        const tableBody = (analysis.results || [])
            .map(result => {
                const analysisCost = analysisCosts.find(ac => ac.testName === result.testName);
                const analysisType = analysisTypes.find(at => at.testName === result.testName);
                const resultValue = result.value ?? 'N/A';
                const units = analysisType?.units ?? '';
                const displayValue = (typeof resultValue === 'number' ? resultValue.toFixed(2) : resultValue) + (units ? ` ${units}`: '');

                return [result.testName, analysisCost?.method ?? 'N/A', displayValue];
            });

        autoTable(doc, {
            startY: 85,
            head: [['Parameter', 'Method', 'Result']],
            body: tableBody,
            theme: 'grid',
            headStyles: {
                fillColor: '#1e40af',
                textColor: '#ffffff',
                fontStyle: 'bold',
                halign: 'center'
            },
            alternateRowStyles: {
                fillColor: '#f5f5f5'
            },
            didDrawPage: (data) => {
                // Header
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(22);
                doc.setTextColor('#1e40af');
                doc.text('LabSys', margin, 22);

                doc.setFont('helvetica', 'normal');
                doc.setFontSize(9);
                doc.setTextColor('#333333');
                doc.text('Quality Control Laboratory', margin, 28);
                doc.text('123 Science Rd, Tech Park, 54321', margin, 32);

                doc.setFont('helvetica', 'bold');
                doc.setFontSize(16);
                doc.text('Analysis Report', pageWidth - margin, 22, { align: 'right' });

                doc.setFont('helvetica', 'normal');
                doc.setFontSize(10);
                doc.text(`Folio: ${analysis.folio}`, pageWidth - margin, 28, { align: 'right' });
                doc.text(`Reception: ${analysis.receptionDate}`, pageWidth - margin, 32, { align: 'right' });
                doc.text(`Delivery: ${analysis.deliveryDate ?? 'N/A'}`, pageWidth - margin, 36, { align: 'right' });

                doc.setDrawColor('#cccccc');
                doc.line(margin, 42, pageWidth - margin, 42);

                // Client and Sample Info
                doc.setFontSize(10);
                doc.setTextColor('#333333');

                doc.setFont('helvetica', 'bold');
                doc.text('BILLED TO', margin, 50);
                doc.setFont('helvetica', 'normal');
                doc.text(client?.name ?? 'Unknown Client', margin, 56);
                doc.text(client?.contactPerson ?? '', margin, 61);

                doc.setFont('helvetica', 'bold');
                doc.text('SAMPLE DETAILS', 110, 50);
                doc.setFont('helvetica', 'normal');
                doc.text(`Sample Name: ${analysis.sampleName}`, 110, 56);
                doc.text(`Product Type: ${analysis.product}`, 110, 61);

                doc.line(margin, 70, pageWidth - margin, 70);

                // Footer
                const pageCount = (doc as any).internal.getNumberOfPages();
                doc.setFontSize(9);
                doc.setTextColor('#888888');

                const footerY = pageHeight - 25;
                doc.line(margin, footerY, pageWidth - margin, footerY);

                doc.line(margin, footerY + 15, margin + 60, footerY + 15);
                doc.text('Analyzed by:', margin, footerY + 20);
                doc.text(technician?.name ?? 'Unknown', margin, footerY + 24);

                doc.text(`Page ${data.pageNumber} of ${pageCount}`, pageWidth - margin, footerY + 22, { align: 'right' });
            }
        });

        doc.save(`report-${analysis.folio}.pdf`);
    };

    const inputStyle = "mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm";

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold text-gray-800">Analysis Management</h1>
                <div className="flex items-center space-x-2">
                    <button onClick={handleDownloadPdf} className="bg-white text-gray-700 hover:bg-gray-100 border border-gray-300 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <DownloadIcon /> <span className="ml-2">Download PDF</span>
                    </button>
                    <button onClick={handleExportCSV} className="bg-green-600 text-white hover:bg-green-700 font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <SheetIcon /> <span className="ml-2">Export CSV</span>
                    </button>
                    <button onClick={() => setActiveView('newAnalysis')} className="bg-primary text-white hover:bg-secondary font-bold py-2 px-4 rounded-lg inline-flex items-center transition-colors">
                        <PlusIcon /> <span className="ml-2">New Analysis</span>
                    </button>
                </div>
            </div>
            <Table headers={headers} data={dataRows} onEdit={handleEdit} onDelete={handleDelete} onPrint={handlePrint} />
            {isModalOpen && editingAnalysis && (
                <Modal onClose={handleCloseModal} title={`Edit Analysis - ${editingAnalysis.folio}`}>
                    <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label htmlFor="deliveryDate" className="block text-sm font-medium text-gray-700">Delivery Date</label>
                            <input type="date" name="deliveryDate" id="deliveryDate" value={modalFormData.deliveryDate?.split('T')[0] || ''} onChange={handleModalFormChange} className={inputStyle} />
                        </div>
                        <div>
                            <label htmlFor="status" className="block text-sm font-medium text-gray-700">Status</label>
                            <select name="status" id="status" value={modalFormData.status} onChange={handleModalFormChange} className={inputStyle}>
                                {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                      </div>
                      <div className="border-t pt-4">
                        <h3 className="text-lg font-medium text-gray-800 mb-2">Analysis Results</h3>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                            {(modalFormData.results || []).map((resultItem) => {
                                const analysisType = analysisTypes.find(at => at.testName === resultItem.testName);
                                const inputType = analysisType?.resultType === 'numeric' ? 'number' : 'text';
                                const units = analysisType?.units;

                                return (
                                    <div key={resultItem.testName}>
                                        <label htmlFor={resultItem.testName} className="block text-sm font-medium text-gray-700">{resultItem.testName} {units ? `(${units})` : ''}</label>
                                        <input 
                                            type={inputType}
                                            id={resultItem.testName}
                                            name={resultItem.testName}
                                            value={resultItem.value ?? ''}
                                            onChange={(e) => handleModalResultChange(resultItem.testName, e.target.value)}
                                            className={inputStyle}
                                            placeholder={inputType === 'number' ? '0.00' : 'Result'}
                                            step={inputType === 'number' ? '0.01' : undefined}
                                        />
                                    </div>
                                )
                            })}
                        </div>
                      </div>
                    </div>
                    <div className="flex justify-end p-4 bg-gray-50 border-t">
                        <button onClick={handleCloseModal} className="bg-gray-200 text-gray-800 hover:bg-gray-300 font-bold py-2 px-4 rounded-lg transition-colors mr-2">
                            Cancel
                        </button>
                        <button onClick={handleSaveAndSubmit} disabled={submitStatus === 'submitting' || submitStatus === 'success'} className={`font-bold py-2 px-4 rounded-lg transition-colors text-white ${
                             submitStatus === 'submitting' ? 'bg-gray-400 cursor-not-allowed' : 
                             submitStatus === 'success' ? 'bg-green-600' : 
                             submitStatus === 'error' ? 'bg-red-600 hover:bg-red-700' :
                             'bg-primary hover:bg-secondary'
                        }`}>
                            {submitStatus === 'submitting' ? 'Saving...' : submitStatus === 'success' ? 'Saved!' : 'Save & Submit to Sheet'}
                        </button>
                    </div>
                </Modal>
            )}
        </div>
    );
};

export default AnalysisManagement;

import React, { useState } from 'react';

const appsScriptCode = `
/**
 * LabSys - Google Apps Script Backend
 * Author: Your World-Class Senior Frontend Engineer
 * Version: 4.1 (Hardened Upsert Logic)
 * Description: This script provides a generic and robust backend for the LabSys web app.
 * It now supports a dynamic list of analysis types managed from a dedicated "AnalysisTypes" sheet
 * and stores analysis results in a flexible JSON format within a single "results" column.
 */

// These names are now used for validation and logging, but the script is sheet-agnostic.
const EXPECTED_SHEETS = ["Clients", "Technicians", "AnalysisCosts", "AnalysisResults", "AnalysisTypes"];

/**
 * Handles GET requests. Fetches initial data from all relevant sheets.
 */
function doGet(e) {
  try {
    const response = {
      clients: getSheetDataAsObjects("Clients"),
      technicians: getSheetDataAsObjects("Technicians"),
      analysisTypes: getSheetDataAsObjects("AnalysisTypes"),
      analysisCosts: getSheetDataAsObjects("AnalysisCosts"),
      analysisResults: getSheetDataAsObjects("AnalysisResults")
    };

    return ContentService.createTextOutput(JSON.stringify(response))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    Logger.log("doGet Error: " + error.stack);
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: "doGet Error: " + error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Handles POST requests. Acts as a generic router for create, update, delete, and test actions.
 * Expects a 'payload' parameter containing a stringified JSON object with 'action', 'targetSheet', and 'payload'.
 */
function doPost(e) {
  try {
    if (!e || !e.parameter || !e.parameter.payload) {
      throw new Error("Invalid POST request. 'payload' parameter is missing.");
    }
    const request = JSON.parse(e.parameter.payload);
    const { action, targetSheet, payload } = request;

    if (action === 'testConnection') {
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Connection successful." }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    if (!action || !targetSheet || !payload) {
      throw new Error("Request must include 'action', 'targetSheet', and 'payload' properties.");
    }

    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(targetSheet);
    if (!sheet) {
      throw new Error("Sheet '" + targetSheet + "' not found. Please ensure the tab exists and the name is correct (case-sensitive).");
    }

    switch (action) {
      case 'delete':
        return handleDelete(payload, sheet);
      case 'create':
      case 'update':
        return handleUpsert(payload, sheet);
      default:
        throw new Error("Unknown action: '" + action + "'.");
    }

  } catch (error) {
    Logger.log("doPost Error: " + error.stack + " | Raw Payload: " + (e.parameter ? e.parameter.payload : "N/A"));
    return ContentService.createTextOutput(JSON.stringify({ status: "error", message: error.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Creates or updates a record in the given sheet. It dynamically reads headers to map data correctly.
 */
function handleUpsert(data, sheet) {
    if (sheet.getLastRow() === 0) { // If sheet is empty, it can't get headers.
      throw new Error("Cannot save to an empty sheet. Please add header columns first.");
    }
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
    const idColumnIndex = headers.indexOf('id');

    if (idColumnIndex === -1) {
      throw new Error("Target sheet must have an 'id' column.");
    }

    const rowData = headers.map(header => {
      const originalKey = Object.keys(data).find(k => k.toLowerCase() === header);
      const value = originalKey ? data[originalKey] : undefined;

      // Explicitly handle complex array types first to ensure they are processed correctly.
      if (header === 'results') {
        if (value && Array.isArray(value)) {
          return JSON.stringify(value);
        }
        return ""; // If value is not a valid array, save an empty string to avoid errors.
      }

      if (header === 'requestedtests') {
        if (value && Array.isArray(value)) {
          return value.join(',');
        }
        return "";
      }

      // Handle all other types
      if (Array.isArray(value)) {
        // Fallback for any other unexpected array types
        return value.join(',');
      }
      return value !== undefined && value !== null ? value : "";
    });

    const sheetData = sheet.getDataRange().getValues();
    let recordUpdated = false;

    // Start from 1 to skip header row
    for (let i = 1; i < sheetData.length; i++) {
      if (sheetData[i][idColumnIndex] == data.id) {
        sheet.getRange(i + 1, 1, 1, headers.length).setValues([rowData]);
        recordUpdated = true;
        break;
      }
    }

    if (!recordUpdated) {
      sheet.appendRow(rowData);
    }

    const message = recordUpdated ? "Data updated successfully in " + sheet.getName() : "Data added successfully to " + sheet.getName();
    return ContentService.createTextOutput(JSON.stringify({ status: "success", message: message }))
      .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Deletes a record from the given sheet based on its ID.
 */
function handleDelete(data, sheet) {
  if (!data.id) {
    throw new Error("Delete action requires an 'id' in the payload.");
  }

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => String(h).toLowerCase().trim());
  const idColumnIndex = headers.indexOf('id');

  if (idColumnIndex === -1) {
    throw new Error("Cannot delete: target sheet must have an 'id' column.");
  }

  const sheetData = sheet.getDataRange().getValues();
  for (let i = sheetData.length - 1; i >= 1; i--) {
    if (sheetData[i][idColumnIndex] == data.id) {
      sheet.deleteRow(i + 1);
      return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row deleted successfully from " + sheet.getName() }))
        .setMimeType(ContentService.MimeType.JSON);
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ status: "success", message: "Row already deleted or not found." }))
    .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Helper to get all data from a sheet and convert to an array of objects with camelCase keys.
 */
function getSheetDataAsObjects(sheetName) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet || sheet.getLastRow() < 2) return []; // Return empty if no data rows

  const dataRange = sheet.getDataRange();
  const data = dataRange.getValues();

  // Normalize headers: lowercase and trim whitespace for robustness
  const headers = data.shift().map(header => String(header).toLowerCase().trim()); 

  const numericHeaders = ['cost'];

  // This map ensures that keys sent to the frontend are in the correct camelCase format
  // that the React components expect, solving inconsistencies from case-insensitive reading.
  const headerMap = {
    'contactperson': 'contactPerson',
    'hiredate': 'hireDate',
    'testname': 'testName',
    'resulttype': 'resultType',
    'receptiondate': 'receptionDate',
    'deliverydate': 'deliveryDate',
    'samplename': 'sampleName',
    'clientid': 'clientId',
    'technicianid': 'technicianId',
    'requestedtests': 'requestedTests'
  };

  return data.map(row => {
    const obj = {};
    headers.forEach((header, index) => {
      let value = row[index];
      if (numericHeaders.includes(header) && !isNaN(value) && value !== '') {
        value = Number(value);
      } else if (header === 'requestedtests' && typeof value === 'string') {
        value = value ? value.split(',').map(item => item.trim()) : [];
      } else if (header === 'results' && typeof value === 'string') {
        try {
          value = value ? JSON.parse(value) : [];
        } catch (e) {
          Logger.log("Could not parse results JSON for row: " + value);
          value = []; // Default to empty array on parsing error
        }
      }

      const key = headerMap[header] || header;
      obj[key] = value;
    });
    return obj;
  });
}
`.trim();

const CodeBlock: React.FC = () => {
    const [copyStatus, setCopyStatus] = useState('Copy');

    const handleCopy = () => {
        navigator.clipboard.writeText(appsScriptCode).then(() => {
            setCopyStatus('Copied!');
            setTimeout(() => setCopyStatus('Copy'), 2000);
        }, () => {
            setCopyStatus('Failed!');
            setTimeout(() => setCopyStatus('Copy'), 2000);
        });
    };

    return (
        <div className="bg-gray-800 rounded-lg overflow-hidden mt-4 relative">
            <button
                onClick={handleCopy}
                className="absolute top-2 right-2 bg-gray-600 text-white text-xs font-semibold py-1 px-3 rounded-md hover:bg-gray-500 transition-colors"
            >
                {copyStatus}
            </button>
            <pre className="p-4 text-sm text-white overflow-x-auto">
                <code>{appsScriptCode}</code>
            </pre>
        </div>
    );
};

export default CodeBlock;

import React, { useState } from 'react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Analysis, Client, Technician, View, AnalysisStatus, AnalysisCost, AnalysisType, AnalysisResultItem } from '../types';
import Table from './ui/Table';
import Modal from './ui/Modal';
import { DownloadIcon, SheetIcon, PlusIcon } from './icons/Icons';

const statusOptions: AnalysisStatus[] = ['Received', 'In Progress', 'Completed', 'Cancelled'];

interface AnalysisManagementProps {
    analyses: Analysis[];
    clients: Client[];
    technicians: Technician[];
    analysisCosts: AnalysisCost[];
    analysisTypes: AnalysisType[];
    reloadData: () => Promise<void>;
    setActiveView: (view: View) => void;
}

const AnalysisManagement: React.FC<AnalysisManagementProps> = ({ analyses, clients, technicians, analysisCosts, analysisTypes, reloadData, setActiveView }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAnalysis, setEditingAnalysis] = useState<Analysis | null>(null);
    const [modalFormData, setModalFormData] = useState<Partial<Analysis>>({});
